import React, { useState, useEffect } from 'react';
import Clock from './Clock';
import { LockIcon, ShieldCheckIcon } from './Icons';

interface LockScreenProps {
  onUnlock: (password: string) => boolean;
  isSetup?: boolean;
}

const LockScreen: React.FC<LockScreenProps> = ({ onUnlock, isSetup }) => {
  const [input, setInput] = useState('');
  const [error, setError] = useState(false);
  const [success, setSuccess] = useState(false);

  const handleKeypad = (num: string) => {
    if (input.length < 8) {
      setInput(prev => prev + num);
      setError(false);
    }
  };

  const handleBackspace = () => {
    setInput(prev => prev.slice(0, -1));
    setError(false);
  };

  const handleUnlock = () => {
    const isValid = onUnlock(input);
    if (isValid) {
      setSuccess(true);
    } else {
      setError(true);
      setTimeout(() => setInput(''), 300);
    }
  };

  useEffect(() => {
    if (input.length >= 4 && !isSetup) {
        // Automatic check for convenience once min length reached (optional)
        // For simplicity, we use the unlock button.
    }
  }, [input, isSetup]);

  return (
    <div className="fixed inset-0 z-[100] bg-gray-900/40 backdrop-blur-2xl flex flex-col items-center justify-center p-4">
      <div className="absolute top-12">
        <Clock />
      </div>

      <div className={`w-full max-w-xs space-y-8 transition-all duration-300 ${error ? 'animate-wiggle' : ''} ${success ? 'scale-110 opacity-0' : 'opacity-100'}`}>
        <div className="flex flex-col items-center gap-4">
          <div className="p-4 rounded-full bg-blue-500/20 text-blue-400">
            {isSetup ? <ShieldCheckIcon className="w-10 h-10" /> : <LockIcon className="w-10 h-10" />}
          </div>
          <h2 className="text-2xl font-bold text-white">
            {isSetup ? 'Set New Passcode' : 'Launcher Locked'}
          </h2>
          <p className="text-gray-400 text-sm">
            {isSetup ? 'Enter a 4-8 digit numeric code' : 'Enter your passcode to continue'}
          </p>
        </div>

        {/* Pin Display */}
        <div className="flex justify-center gap-4 h-12">
          {Array.from({ length: Math.max(input.length, 4) }).map((_, i) => (
            <div 
              key={i} 
              className={`w-4 h-4 rounded-full border-2 transition-all duration-200 ${
                i < input.length 
                  ? 'bg-white border-white scale-110' 
                  : 'border-gray-600 bg-transparent'
              }`} 
            />
          ))}
        </div>

        {/* Keypad */}
        <div className="grid grid-cols-3 gap-4">
          {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
            <button
              key={num}
              onClick={() => handleKeypad(num.toString())}
              className="aspect-square rounded-full bg-gray-800/50 hover:bg-gray-700/60 text-white text-2xl font-medium transition-colors border border-gray-700/50 flex items-center justify-center active:scale-90"
            >
              {num}
            </button>
          ))}
          <button onClick={handleBackspace} className="aspect-square flex items-center justify-center text-gray-400 hover:text-white transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-8 h-8">
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 9.75L14.25 12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12L12 14.25m-2.58 4.92l-6.37-6.37a2.25 2.25 0 010-3.18l6.37-6.37A2.25 2.25 0 0110.47 2.25h10.28c1.242 0 2.25 1.008 2.25 2.25v15a2.25 2.25 0 01-2.25 2.25H10.47a2.25 2.25 0 01-1.47-.58z" />
            </svg>
          </button>
          <button
            onClick={() => handleKeypad('0')}
            className="aspect-square rounded-full bg-gray-800/50 hover:bg-gray-700/60 text-white text-2xl font-medium transition-colors border border-gray-700/50 flex items-center justify-center active:scale-90"
          >
            0
          </button>
          <button 
            onClick={handleUnlock} 
            disabled={input.length < 4}
            className="aspect-square flex items-center justify-center rounded-full bg-blue-600/20 text-blue-400 hover:bg-blue-600 hover:text-white transition-all border border-blue-500/30 active:scale-95 disabled:opacity-20 disabled:scale-100"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-8 h-8">
              <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
};

export default LockScreen;

import React from 'react';
import { LockIcon, ShieldCheckIcon, PencilIcon, TrashIcon } from './Icons';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  isEditMode: boolean;
  onToggleEditMode: () => void;
  passwordEnabled: boolean;
  onManagePassword: () => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ 
  isOpen, 
  onClose, 
  isEditMode, 
  onToggleEditMode, 
  passwordEnabled,
  onManagePassword 
}) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4" onClick={onClose}>
      <div 
        className="bg-gray-800 border border-gray-700 rounded-2xl w-full max-w-md overflow-hidden shadow-2xl" 
        onClick={e => e.stopPropagation()}
      >
        <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-900/20">
          <h2 className="text-xl font-bold text-white flex items-center gap-2">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6 text-gray-400">
                <path strokeLinecap="round" strokeLinejoin="round" d="M10.5 6h9.75M10.5 6a1.5 1.5 0 11-3 0m3 0a1.5 1.5 0 10-3 0M3.75 6H7.5m3 12h9.75m-9.75 0a1.5 1.5 0 11-3 0m3 0a1.5 1.5 0 10-3 0m-3.75 0H7.5m9-6h3.75m-3.75 0a1.5 1.5 0 11-3 0m3 0a1.5 1.5 0 10-3 0M3.75 12H15" />
            </svg>
            Launcher Settings
          </h2>
          <button onClick={onClose} className="text-gray-400 hover:text-white transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-6 h-6">
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="p-6 space-y-6">
          {/* Edit Mode Toggle */}
          <div className="flex items-center justify-between">
            <div className="space-y-0.5">
              <p className="text-white font-medium">Customization Mode</p>
              <p className="text-sm text-gray-400">Edit, move, and delete apps</p>
            </div>
            <button 
              onClick={onToggleEditMode}
              className={`relative inline-flex h-6 w-11 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none ${isEditMode ? 'bg-blue-600' : 'bg-gray-700'}`}
            >
              <span className={`inline-block h-5 w-5 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${isEditMode ? 'translate-x-5' : 'translate-x-0'}`} />
            </button>
          </div>

          <div className="h-px bg-gray-700" />

          {/* Password Settings */}
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <div className="space-y-0.5">
                <p className="text-white font-medium">Passcode Protection</p>
                <p className="text-sm text-gray-400">Require a PIN to open launcher</p>
              </div>
              <div className={`p-2 rounded-lg ${passwordEnabled ? 'bg-green-500/10 text-green-400' : 'bg-red-500/10 text-red-400'}`}>
                {passwordEnabled ? <ShieldCheckIcon className="w-5 h-5" /> : <LockIcon className="w-5 h-5 opacity-40" />}
              </div>
            </div>

            <button 
              onClick={onManagePassword}
              className="w-full flex items-center justify-center gap-2 py-3 bg-gray-700 hover:bg-gray-600 text-white rounded-xl transition-colors font-medium"
            >
              {passwordEnabled ? 'Change / Remove Passcode' : 'Set Launcher Passcode'}
            </button>
          </div>

          <div className="h-px bg-gray-700" />

          <div className="text-xs text-gray-500 text-center">
            Plus+Launcher v1.2.0 • Data stored locally
          </div>
        </div>
      </div>
