import React, { useState, useMemo, useEffect } from 'react';
import Header from './components/Header';
import Clock from './components/Clock';
import SearchBar from './components/SearchBar';
import AppCard from './components/AppCard';
import AddAppModal from './components/AddAppModal';
import LockScreen from './components/LockScreen';
import SettingsModal from './components/SettingsModal';
import type { AppItem, StoredApp, LauncherSettings } from './types';
import { 
  MailIcon, CalendarIcon, PhotosIcon, MusicIcon, SettingsIcon, 
  BrowserIcon, FilesIcon, MapsIcon, GameIcon, PlayStoreIcon, 
  UserIcon, CodeIcon, LinkIcon, iconMap 
} from './components/Icons';

const LOCAL_STORAGE_KEY = 'plus-launcher-custom-apps';
const SETTINGS_KEY = 'plus-launcher-settings';

const UrlIcon: React.FC<{ src: string; name: string; className?: string }> = ({ src, name, className }) => {
  const [hasError, setHasError] = useState(false);

  useEffect(() => {
    setHasError(false);
  }, [src]);

  if (hasError || !src) {
    return <LinkIcon className={className} />;
  }

  return (
    <img 
      src={src} 
      alt={name} 
      className={`${className} object-cover rounded-md`} 
      onError={() => setHasError(true)}
    />
  );
};

export default function App() {
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditMode, setIsEditMode] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isLockSetupOpen, setIsLockSetupOpen] = useState(false);
  const [isLocked, setIsLocked] = useState(false);
  const [customApps, setCustomApps] = useState<StoredApp[]>([]);
  const [editingApp, setEditingApp] = useState<StoredApp | null>(null);
  const [settings, setSettings] = useState<LauncherSettings>({
    passwordEnabled: false,
    passwordHash: ''
  });

  const loadApps = () => {
    try {
      const stored = localStorage.getItem(LOCAL_STORAGE_KEY);
      if (stored) {
        const parsed = JSON.parse(stored);
        if (Array.isArray(parsed)) setCustomApps(parsed);
      }

      const storedSettings = localStorage.getItem(SETTINGS_KEY);
      if (storedSettings) {
        const parsed = JSON.parse(storedSettings);
        setSettings(parsed);
        if (parsed.passwordEnabled && parsed.passwordHash) {
          setIsLocked(true);
        }
      }
    } catch (error) {
      console.error("Failed to load apps/settings", error);
    }
  };

  useEffect(() => {
    loadApps();
  }, []);

  const saveApps = (newApps: StoredApp[]) => {
    setCustomApps(newApps);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(newApps));
  };

  const saveSettings = (newSettings: LauncherSettings) => {
    setSettings(newSettings);
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(newSettings));
  };

  const handleSaveApp = (app: StoredApp) => {
    let newApps;
    if (editingApp) {
      newApps = customApps.map(a => a.id === app.id ? app : a);
    } else {
      newApps = [...customApps, app];
    }
    saveApps(newApps);
    setIsModalOpen(false);
    setEditingApp(null);
  };

  const handleDeleteApp = (id: string) => {
    if (confirm('Are you sure you want to delete this app?')) {
      const newApps = customApps.filter(app => app.id !== id);
      saveApps(newApps);
    }
  };

  const handleUnlockAttempt = (attempt: string): boolean => {
    // Simple hash for local comparison
    const hashedAttempt = btoa(attempt);
    if (hashedAttempt === settings.passwordHash) {
      setIsLocked(false);
      return true;
    }
    return false;
  };

  const handleSetPasscode = (passcode: string): boolean => {
    if (passcode.length < 4) return false;

    // Toggle logic: if user enters the same password while managing, they might want to clear it,
    // but usually we just set it. 
    // To disable, we'd need a specific flow. 
    // For this simple version: entering a passcode sets it.

    const hashed = btoa(passcode);
    saveSettings({
        passwordEnabled: true,
        passwordHash: hashed
    });
    setIsLockSetupOpen(false);
    return true;
  };

  const togglePasswordFeature = () => {
    if (settings.passwordEnabled) {
        if (confirm('Disable passcode protection?')) {
            saveSettings({
                passwordEnabled: false,
                passwordHash: ''
            });
        }
    } else {
        setIsLockSetupOpen(true);
    }
  };

  const defaultApps: AppItem[] = [
    {
      id: 'chrome',
      name: 'Chrome',
      icon: BrowserIcon,
      color: '#2563eb',
      action: () => window.open('https://www.google.com', '_blank'),
      isCustom: false
    },
    {
      id: 'roblox',
      name: 'Roblox',
      icon: GameIcon,
      color: '#ef4444',
      action: () => window.open('https://www.roblox.com', '_blank'),
      isCustom: false
    },
    {
      id: 'minecraft',
      name: 'Minecraft',
      icon: GameIcon,
      color: '#10b981',
      action: () => window.open('https://www.minecraft.net', '_blank'),
      isCustom: false
    },
    {
      id: 'playstore',
      name: 'Google Play',
      icon: PlayStoreIcon,
      color: '#0ea5e9',
      action: () => window.open('https://play.google.com', '_blank'),
      isCustom: false
    },
    {
      id: 'colab',
      name: 'Google Colab',
      icon: CodeIcon,
      color: '#f97316',
      action: () => window.open('https://colab.research.google.com/', '_blank'),
      isCustom: false
    },
    {
      id: 'photos',
      name: 'Photos',
      icon: PhotosIcon,
      color: '#ec4899',
      action: () => window.open('https://photos.google.com', '_blank'),
      isCustom: false
    },
    {
        id: 'launcher-settings',
        name: 'Launcher Settings',
        icon: SettingsIcon,
        color: '#475569',
        action: () => setIsSettingsOpen(true),
        isCustom: false
    }
  ];

  const mappedCustomApps: AppItem[] = customApps.map(app => {
    let IconComponent = LinkIcon;
    if (app.iconIdentifier && iconMap[app.iconIdentifier]) {
        IconComponent = iconMap[app.iconIdentifier];
    } else if (app.iconIdentifier && app.iconIdentifier.startsWith('http')) {
        IconComponent = ({ className }) => <UrlIcon src={app.iconIdentifier} name={app.name} className={className} />;
    }

    return {
        id: app.id,
        name: app.name,
        icon: IconComponent,
        color: app.color,
        action: () => window.open(app.url, '_blank'),
        isCustom: true
    };
  });

  const allApps = [...defaultApps, ...mappedCustomApps];

  const filteredApps = allApps.filter(app => 
    app.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-gray-900 p-6 md:p-12 font-sans selection:bg-blue-500/30 overflow-x-hidden">
        {/* Lock Screen Overlay */}
        {isLocked && <LockScreen onUnlock={handleUnlockAttempt} />}

        {/* Passcode Setup Overlay */}
        {isLockSetupOpen && <LockScreen onUnlock={handleSetPasscode} isSetup={true} />}

        <div className="max-w-7xl mx-auto space-y-12">
            <Header 
                isEditMode={isEditMode} 
                onToggleEditMode={() => setIsEditMode(!isEditMode)}
                hasCustomApps={customApps.length > 0}
                onReload={loadApps}
            />

            <div className="space-y-8">
                <Clock />
                <SearchBar value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4 sm:gap-6">
                {filteredApps.map(app => (
                    <AppCard 
                        key={app.id} 
                        app={app} 
                        isEditMode={isEditMode}
                        onEdit={() => {
                            const stored = customApps.find(a => a.id === app.id);
                            if (stored) {
                                setEditingApp(stored);
                                setIsModalOpen(true);
                            }
                        }}
                        onDelete={() => handleDeleteApp(app.id)}
                    />
                ))}

                <button
                    onClick={() => { setEditingApp(null); setIsModalOpen(true); }}
                    className="aspect-square flex flex-col items-center justify-center p-4 rounded-2xl border-2 border-dashed border-gray-700 text-gray-500 hover:text-white hover:border-gray-500 hover:bg-gray-800/30 transition-all duration-300 group"
                >
                    <div className="p-4 rounded-full bg-gray-800 group-hover:bg-gray-700 transition-colors mb-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                        </svg>
                    </div>
                    <span className="text-sm font-medium">Add App</span>
                </button>
            </div>
        </div>

        <AddAppModal 
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            onSave={handleSaveApp}
            appToEdit={editingApp}
        />

        <SettingsModal 
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            isEditMode={isEditMode}
            onToggleEditMode={() => setIsEditMode(!isEditMode)}
            passwordEnabled={settings.passwordEnabled}
            onManagePassword={togglePasswordFeature}
        />
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import Clock from './Clock';
import { LockIcon, ShieldCheckIcon } from './Icons';

interface LockScreenProps {
  onUnlock: (password: string) => boolean;
  isSetup?: boolean;
}

const LockScreen: React.FC<LockScreenProps> = ({ onUnlock, isSetup }) => {
  const [input, setInput] = useState('');
  const [error, setError] = useState(false);
  const [success, setSuccess] = useState(false);

  const handleKeypad = (num: string) => {
    if (input.length < 8) {
      setInput(prev => prev + num);
      setError(false);
    }
  };

  const handleBackspace = () => {
    setInput(prev => prev.slice(0, -1));
    setError(false);
  };

  const handleUnlock = () => {
    const isValid = onUnlock(input);
    if (isValid) {
      setSuccess(true);
    } else {
      setError(true);
      setTimeout(() => setInput(''), 300);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] bg-gray-900/60 backdrop-blur-3xl flex flex-col items-center justify-center p-4">
      {/* Clock - Slightly smaller and closer to top */}
      <div className="absolute top-8">
        <Clock />
      </div>

      <div className={`w-full max-w-[280px] space-y-6 transition-all duration-300 ${error ? 'animate-wiggle' : ''} ${success ? 'scale-110 opacity-0' : 'opacity-100'}`}>
        <div className="flex flex-col items-center gap-2">
          <div className="p-3 rounded-full bg-blue-500/20 text-blue-400">
            {isSetup ? <ShieldCheckIcon className="w-8 h-8" /> : <LockIcon className="w-8 h-8" />}
          </div>
          <h2 className="text-xl font-bold text-white">
            {isSetup ? 'Set Passcode' : 'Launcher Locked'}
          </h2>
          <p className="text-gray-400 text-xs text-center px-4">
            {isSetup ? 'Enter 4-8 digits' : 'Enter your passcode'}
          </p>
        </div>

        {/* Pin Display - Smaller dots */}
        <div className="flex justify-center gap-3 h-8">
          {Array.from({ length: Math.max(input.length, 4) }).map((_, i) => (
            <div 
              key={i} 
              className={`w-3 h-3 rounded-full border-2 transition-all duration-200 ${
                i < input.length 
                  ? 'bg-white border-white scale-110' 
                  : 'border-gray-600 bg-transparent'
              }`} 
            />
          ))}
        </div>

        {/* Compact Keypad */}
        <div className="grid grid-cols-3 gap-3">
          {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
            <button
              key={num}
              onClick={() => handleKeypad(num.toString())}
              className="aspect-square rounded-full bg-gray-800/40 hover:bg-gray-700/60 text-white text-xl font-semibold transition-all border border-gray-700/30 flex items-center justify-center active:scale-90"
            >
              {num}
            </button>
          ))}
          <button onClick={handleBackspace} className="aspect-square flex items-center justify-center text-gray-500 hover:text-white transition-colors active:scale-90">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 9.75L14.25 12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12L12 14.25m-2.58 4.92l-6.37-6.37a2.25 2.25 0 010-3.18l6.37-6.37A2.25 2.25 0 0110.47 2.25h10.28c1.242 0 2.25 1.008 2.25 2.25v15a2.25 2.25 0 01-2.25 2.25H10.47a2.25 2.25 0 01-1.47-.58z" />
            </svg>
          </button>
          <button
            onClick={() => handleKeypad('0')}
            className="aspect-square rounded-full bg-gray-800/40 hover:bg-gray-700/60 text-white text-xl font-semibold transition-all border border-gray-700/30 flex items-center justify-center active:scale-90"
          >
            0
          </button>
          <button 
            onClick={handleUnlock} 
            disabled={input.length < 4}
            className="aspect-square flex items-center justify-center rounded-full bg-blue-600/30 text-blue-400 hover:bg-blue-600 hover:text-white transition-all border border-blue-500/30 active:scale-95 disabled:opacity-10 disabled:scale-100"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-6 h-6">
              <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
};

