import React, { useState, useEffect, useRef } from 'react';
import Clock from './Clock';
import { LockIcon, ShieldCheckIcon, FingerprintIcon } from './Icons';

interface LockScreenProps {
  onUnlock: (password: string) => boolean;
  isSetup?: boolean;
  isFingerprintSetup?: boolean;
  fingerprintEnabled?: boolean;
}

const LockScreen: React.FC<LockScreenProps> = ({ onUnlock, isSetup, isFingerprintSetup, fingerprintEnabled }) => {
  const [input, setInput] = useState('');
  const [error, setError] = useState(false);
  const [success, setSuccess] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scanProgress, setScanProgress] = useState(0);
  const scanTimerRef = useRef<number | null>(null);

  const handleKeypad = (num: string) => {
    if (input.length < 8) {
      setInput(prev => prev + num);
      setError(false);
    }
  };

  const handleBackspace = () => {
    setInput(prev => prev.slice(0, -1));
    setError(false);
  };

  const handleUnlock = () => {
    const isValid = onUnlock(input);
    if (isValid) {
      setSuccess(true);
    } else {
      setError(true);
      setTimeout(() => setInput(''), 300);
    }
  };

  const stopFingerprintScan = () => {
    if (scanTimerRef.current) {
      clearInterval(scanTimerRef.current);
      scanTimerRef.current = null;
    }
    if (!success) {
      setIsScanning(false);
      setScanProgress(0);
    }
  };

  const startFingerprintScan = (e: React.MouseEvent | React.TouchEvent) => {
    // Check if it's a touch event to prevent double-firing on some mobile browsers
    if (e.type === 'touchstart') {
      // Ensure we don't prevent default if we want scroll, but here we are in a modal lock screen
      // so preventing default is usually fine to avoid browser "long press" menus
    }

    if (isScanning || success) return;

    setIsScanning(true);
    setError(false);
    setScanProgress(0);

    const duration = isFingerprintSetup ? 2000 : 1200; // Enrollment takes longer
    const interval = 20;
    const steps = duration / interval;
    let currentStep = 0;

    scanTimerRef.current = window.setInterval(() => {
        currentStep++;
        const progress = (currentStep / steps) * 100;
        setScanProgress(progress);

        if (currentStep >= steps) {
            stopFingerprintScan();
            const isValid = onUnlock('biometric');
            if (isValid) {
                setSuccess(true);
            } else {
                setError(true);
            }
        }
    }, interval);
  };

  useEffect(() => {
    return () => {
      if (scanTimerRef.current) clearInterval(scanTimerRef.current);
    };
  }, []);

  const getStatusText = () => {
    if (success) return isFingerprintSetup ? 'Fingerprint Added!' : 'Unlocked';
    if (error) return 'Scan failed, try again';
    if (isScanning) return isFingerprintSetup ? 'Enrolling... Hold Still' : 'Keep holding...';
    if (isFingerprintSetup) return 'Touch and Hold to Enroll Finger';
    if (isSetup) return 'Enter 4-8 digits to set PIN';
    return 'Enter PIN or Hold to Scan';
  };

  return (
    <div className="fixed inset-0 z-[110] bg-gray-900/90 backdrop-blur-3xl flex flex-col items-center justify-center p-4 select-none touch-none">
      {/* Clock - Smaller during setup */}
      <div className={`mb-4 sm:mb-8 transition-all duration-500 ${isFingerprintSetup ? 'scale-50 opacity-50' : 'scale-100'}`}>
        <Clock />
      </div>

      <div className={`w-full max-w-[300px] flex flex-col items-center space-y-6 transition-all duration-300 ${error ? 'animate-wiggle' : ''} ${success ? 'scale-110 opacity-0 pointer-events-none' : 'opacity-100'}`}>
        <div className="flex flex-col items-center gap-2">
          <div className={`p-3 rounded-full transition-all duration-500 ${isScanning ? 'bg-blue-500 shadow-[0_0_20px_rgba(59,130,246,0.5)] scale-110' : 'bg-blue-500/20'} text-white`}>
            {isSetup ? <ShieldCheckIcon className="w-8 h-8" /> : isFingerprintSetup || fingerprintEnabled ? <FingerprintIcon className="w-8 h-8" /> : <LockIcon className="w-8 h-8" />}
          </div>
          <h2 className="text-xl font-bold text-white tracking-tight">
            {isFingerprintSetup ? 'Add Fingerprint' : isSetup ? 'Setup PIN' : 'Launcher Locked'}
          </h2>
          <p className={`text-center px-6 transition-colors duration-300 ${isScanning ? 'text-blue-400' : 'text-gray-400'} text-xs font-medium`}>
            {getStatusText()}
          </p>
        </div>

        {/* Hide PIN UI during Fingerprint Enrollment */}
        {!isFingerprintSetup && (
            <div className="flex justify-center gap-3 h-6">
                {Array.from({ length: Math.max(input.length, 4) }).map((_, i) => (
                    <div 
                        key={i} 
                        className={`w-3 h-3 rounded-full border-2 transition-all duration-200 ${
                            i < input.length 
                                ? 'bg-white border-white scale-125' 
                                : 'border-gray-600 bg-transparent'
                        }`} 
                    />
                ))}
            </div>
        )}

        <div className="flex flex-col items-center gap-8 w-full">
            {/* Keypad - Hidden or ghosted during fingerprint setup */}
            {!isFingerprintSetup && (
                <div className={`grid grid-cols-3 gap-3 w-full max-w-[240px] transition-all duration-300 ${isScanning ? 'opacity-10 grayscale pointer-events-none scale-95' : 'opacity-100'}`}>
                    {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                        <button
                            key={num}
                            type="button"
                            onClick={() => handleKeypad(num.toString())}
                            className="aspect-square rounded-full bg-gray-800/60 hover:bg-gray-700 text-white text-2xl font-semibold transition-all border border-gray-700/50 flex items-center justify-center active:scale-90 shadow-sm"
                        >
                            {num}
                        </button>
                    ))}
                    <button 
                        type="button"
                        onClick={handleBackspace} 
                        className="aspect-square flex items-center justify-center text-gray-500 hover:text-white transition-colors active:scale-90"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-6 h-6">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M12 9.75L14.25 12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12L12 14.25m-2.58 4.92l-6.37-6.37a2.25 2.25 0 010-3.18l6.37-6.37A2.25 2.25 0 0110.47 2.25h10.28c1.242 0 2.25 1.008 2.25 2.25v15a2.25 2.25 0 01-2.25 2.25H10.47a2.25 2.25 0 01-1.47-.58z" />
                        </svg>
                    </button>
                    <button
                        type="button"
                        onClick={() => handleKeypad('0')}
                        className="aspect-square rounded-full bg-gray-800/60 hover:bg-gray-700 text-white text-2xl font-semibold transition-all border border-gray-700/50 flex items-center justify-center active:scale-90 shadow-sm"
                    >
                        0
                    </button>
                    <button 
                        type="button"
                        onClick={handleUnlock} 
                        disabled={input.length < 4}
                        className="aspect-square flex items-center justify-center rounded-full bg-blue-600/40 text-blue-400 hover:bg-blue-600 hover:text-white transition-all border border-blue-500/40 active:scale-95 disabled:opacity-5 disabled:grayscale"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-6 h-6">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                        </svg>
                    </button>
                </div>
            )}

            {/* Fingerprint Scanner Area */}
            {(isFingerprintSetup || (!isSetup && fingerprintEnabled)) && (
                <div className="relative flex flex-col items-center">
                    {/* Progress Ring */}
                    <svg className="absolute inset-[-16px] w-[calc(100%+32px)] h-[calc(100%+32px)] -rotate-90 pointer-events-none">
                        <circle
                            cx="50%"
                            cy="50%"
                            r="44"
                            className="stroke-gray-800 fill-none"
                            strokeWidth="6"
                        />
                        <circle
                            cx="50%"
                            cy="50%"
                            r="44"
                            className={`transition-all duration-75 fill-none ${isScanning ? 'stroke-blue-500' : 'stroke-blue-500/30'}`}
                            strokeWidth="6"
                            strokeDasharray="276.5"
                            strokeDashoffset={276.5 - (276.5 * scanProgress) / 100}
                            strokeLinecap="round"
                        />
                    </svg>

                    {/* Ripples during scan */}
                    {isScanning && (
                        <>
                            <div className="absolute inset-0 bg-blue-500/20 rounded-full animate-ping pointer-events-none" />
                            <div className="absolute inset-[-4px] border border-blue-400/30 rounded-full animate-pulse pointer-events-none" />
                        </>
                    )}

                    <button
                        type="button"
                        onMouseDown={startFingerprintScan}
                        onTouchStart={startFingerprintScan}
                        onMouseUp={stopFingerprintScan}
                        onMouseLeave={stopFingerprintScan}
                        onTouchEnd={stopFingerprintScan}
                        className={`p-8 rounded-full border-2 transition-all duration-300 relative z-10 overflow-hidden ${
                            isScanning 
                                ? 'bg-blue-600 text-white scale-110 border-blue-300 shadow-[0_0_50px_rgba(37,99,235,0.7)]' 
                                : 'bg-gray-800 text-gray-400 border-gray-700 hover:bg-gray-700 hover:text-white active:scale-95'
                        }`}
                    >
                        <FingerprintIcon className={`w-12 h-12 ${isScanning ? 'animate-pulse' : ''}`} />

                        {/* Scanning light bar effect */}
                        {isScanning && (
                            <div className="absolute top-0 left-0 w-full h-1/2 bg-gradient-to-b from-blue-300/30 to-transparent animate-[scan_1.5s_infinite]" />
                        )}
                    </button>

                    {isFingerprintSetup && !isScanning && !success && (
                        <div className="mt-8 animate-bounce text-blue-400">
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-6 h-6 mx-auto">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M12 19.5v-15m0 0l-6.75 6.75M12 4.5l6.75 6.75" />
                            </svg>
                        </div>
                    )}
                </div>
            )}
        </div>
      </div>

      <style>{`
        @keyframes scan {
          0% { transform: translateY(-100%); }
          100% { transform: translateY(200%); }
        }
      `}</style>
    </div>
  );
};

