import React, { useState, useEffect, useRef } from 'react';
import Clock from './Clock';
import { LockIcon, ShieldCheckIcon, FingerprintIcon } from './Icons';

interface LockScreenProps {
  onUnlock: (password: string) => boolean;
  isSetup?: boolean;
  isFingerprintSetup?: boolean;
  fingerprintEnabled?: boolean;
}

const LockScreen: React.FC<LockScreenProps> = ({ onUnlock, isSetup, isFingerprintSetup, fingerprintEnabled }) => {
  const [input, setInput] = useState('');
  const [error, setError] = useState(false);
  const [success, setSuccess] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scanProgress, setScanProgress] = useState(0);
  const [showHoldHint, setShowHoldHint] = useState(false);
  const scanTimerRef = useRef<number | null>(null);
  const hintTimerRef = useRef<number | null>(null);

  const handleKeypad = (num: string) => {
    if (input.length < 8) {
      setInput(prev => prev + num);
      setError(false);
    }
  };

  const handleBackspace = () => {
    setInput(prev => prev.slice(0, -1));
    setError(false);
  };

  const handleUnlock = () => {
    const isValid = onUnlock(input);
    if (isValid) {
      setSuccess(true);
    } else {
      setError(true);
      setTimeout(() => setInput(''), 300);
    }
  };

  const stopFingerprintScan = () => {
    if (scanTimerRef.current) {
      clearInterval(scanTimerRef.current);
      scanTimerRef.current = null;
    }

    // If they let go before finishing
    if (scanProgress > 0 && scanProgress < 100) {
        setShowHoldHint(true);
        if (hintTimerRef.current) clearTimeout(hintTimerRef.current);
        hintTimerRef.current = window.setTimeout(() => setShowHoldHint(false), 2000);
    }

    if (!success) {
      setIsScanning(false);
      setScanProgress(0);
      if (window.navigator.vibrate) window.navigator.vibrate(0); // Stop vibration
    }
  };

  const startFingerprintScan = (e: React.PointerEvent) => {
    // Prevent the browser from handling this as a drag/scroll or context menu
    (e.target as HTMLButtonElement).setPointerCapture(e.pointerId);

    if (isScanning || success) return;

    setIsScanning(true);
    setError(false);
    setShowHoldHint(false);
    setScanProgress(0);

    if (window.navigator.vibrate) {
        window.navigator.vibrate([100, 50, 100, 50, 100]); // Initial "seeking" vibration
    }

    const duration = isFingerprintSetup ? 1500 : 1000; 
    const interval = 20;
    const steps = duration / interval;
    let currentStep = 0;

    scanTimerRef.current = window.setInterval(() => {
        currentStep++;
        const progress = (currentStep / steps) * 100;
        setScanProgress(progress);

        // Continuous light vibration while scanning
        if (currentStep % 10 === 0 && window.navigator.vibrate) {
            window.navigator.vibrate(20);
        }

        if (currentStep >= steps) {
            if (scanTimerRef.current) clearInterval(scanTimerRef.current);
            scanTimerRef.current = null;

            if (window.navigator.vibrate) window.navigator.vibrate(100); // Confirmation buzz

            const isValid = onUnlock('biometric');
            if (isValid) {
                setSuccess(true);
            } else {
                setError(true);
                setIsScanning(false);
                setScanProgress(0);
            }
        }
    }, interval);
  };

  useEffect(() => {
    return () => {
      if (scanTimerRef.current) clearInterval(scanTimerRef.current);
      if (hintTimerRef.current) clearTimeout(hintTimerRef.current);
    };
  }, []);

  const getStatusText = () => {
    if (success) return isFingerprintSetup ? 'Fingerprint Registered!' : 'Access Granted';
    if (error) return 'Biometric mismatch. Use PIN.';
    if (isScanning) return isFingerprintSetup ? 'Registering...' : 'Scanning... Hold Still';
    if (showHoldHint) return 'KEEP HOLDING UNTIL COMPLETE';
    if (isFingerprintSetup) return 'Touch and Hold to Enroll';
    if (isSetup) return 'Set your 4-8 digit PIN';
    return 'Hold to Unlock';
  };

  return (
    <div className="fixed inset-0 z-[110] bg-gray-950/95 backdrop-blur-3xl flex flex-col items-center justify-center p-4 select-none touch-none">
      {/* Visual background effect when scanning */}
      {isScanning && (
        <div className="absolute inset-0 bg-blue-500/5 animate-pulse pointer-events-none" />
      )}

      <div className={`mb-8 transition-all duration-500 ${isFingerprintSetup ? 'scale-50 opacity-30 blur-sm' : 'scale-100'}`}>
        <Clock />
      </div>

      <div className={`w-full max-w-[300px] flex flex-col items-center space-y-6 transition-all duration-500 ${error ? 'animate-wiggle' : ''} ${success ? 'scale-150 opacity-0 pointer-events-none' : 'opacity-100'}`}>
        <div className="flex flex-col items-center gap-2">
          <div className={`p-4 rounded-full transition-all duration-500 ${isScanning ? 'bg-blue-600 shadow-[0_0_30px_rgba(37,99,235,0.8)] scale-110' : 'bg-white/5 border border-white/10'} text-white`}>
            {isSetup ? <ShieldCheckIcon className="w-8 h-8" /> : isFingerprintSetup || fingerprintEnabled ? <FingerprintIcon className="w-8 h-8" /> : <LockIcon className="w-8 h-8" />}
          </div>
          <h2 className="text-2xl font-black text-white tracking-tight uppercase">
            {isFingerprintSetup ? 'Enrollment' : isSetup ? 'PIN Setup' : 'Plus+ Secure'}
          </h2>
          <p className={`text-center px-6 transition-all duration-300 h-4 ${isScanning || showHoldHint ? 'text-blue-400 font-bold' : 'text-gray-500'} text-[10px] tracking-widest uppercase`}>
            {getStatusText()}
          </p>
        </div>

        {!isFingerprintSetup && (
            <div className={`flex justify-center gap-3 h-8 transition-opacity duration-300 ${isScanning ? 'opacity-20' : 'opacity-100'}`}>
                {Array.from({ length: Math.max(input.length, 4) }).map((_, i) => (
                    <div 
                        key={i} 
                        className={`w-3 h-3 rounded-full border-2 transition-all duration-200 ${
                            i < input.length 
                                ? 'bg-blue-500 border-blue-500 scale-125 shadow-[0_0_10px_rgba(59,130,246,0.5)]' 
                                : 'border-gray-700 bg-transparent'
                        }`} 
                    />
                ))}
            </div>
        )}

        <div className="flex flex-col items-center gap-8 w-full">
            {!isFingerprintSetup && (
                <div className={`grid grid-cols-3 gap-3 w-full max-w-[240px] transition-all duration-500 ${isScanning ? 'opacity-0 scale-90 pointer-events-none' : 'opacity-100'}`}>
                    {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                        <button
                            key={num}
                            type="button"
                            onClick={() => handleKeypad(num.toString())}
                            className="aspect-square rounded-2xl bg-white/5 hover:bg-white/10 text-white text-2xl font-bold transition-all border border-white/5 flex items-center justify-center active:scale-90 active:bg-blue-600/20"
                        >
                            {num}
                        </button>
                    ))}
                    <button 
                        type="button"
                        onClick={handleBackspace} 
                        className="aspect-square flex items-center justify-center text-gray-500 hover:text-white transition-colors active:scale-90"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-6 h-6">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M12 9.75L14.25 12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12L12 14.25m-2.58 4.92l-6.37-6.37a2.25 2.25 0 010-3.18l6.37-6.37A2.25 2.25 0 0110.47 2.25h10.28c1.242 0 2.25 1.008 2.25 2.25v15a2.25 2.25 0 01-2.25 2.25H10.47a2.25 2.25 0 01-1.47-.58z" />
                        </svg>
                    </button>
                    <button
                        type="button"
                        onClick={() => handleKeypad('0')}
                        className="aspect-square rounded-2xl bg-white/5 hover:bg-white/10 text-white text-2xl font-bold transition-all border border-white/5 flex items-center justify-center active:scale-90 active:bg-blue-600/20"
                    >
                        0
                    </button>
                    <button 
                        type="button"
                        onClick={handleUnlock} 
                        disabled={input.length < 4}
                        className="aspect-square flex items-center justify-center rounded-2xl bg-blue-600 text-white transition-all shadow-[0_0_20px_rgba(37,99,235,0.4)] active:scale-95 disabled:opacity-20 disabled:shadow-none"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-6 h-6">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                        </svg>
                    </button>
                </div>
            )}

            {(isFingerprintSetup || (!isSetup && fingerprintEnabled)) && (
                <div className="relative flex flex-col items-center">
                    {/* Ring background */}
                    <div className="absolute inset-[-20px] rounded-full border-4 border-white/5 pointer-events-none" />

                    {/* Progress Ring */}
                    <svg className="absolute inset-[-20px] w-[calc(100%+40px)] h-[calc(100%+40px)] -rotate-90 pointer-events-none z-20">
                        <circle
                            cx="50%"
                            cy="50%"
                            r="48"
                            className={`transition-all duration-100 fill-none ${isScanning ? 'stroke-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.5)]' : 'stroke-white/10'}`}
                            strokeWidth="8"
                            strokeDasharray="301.6"
                            strokeDashoffset={301.6 - (301.6 * scanProgress) / 100}
                            strokeLinecap="round"
                        />
                    </svg>

                    {/* Scanner Button using Pointer Events */}
                    <button
                        type="button"
                        onPointerDown={startFingerprintScan}
                        onPointerUp={stopFingerprintScan}
                        onPointerLeave={stopFingerprintScan}
                        onPointerCancel={stopFingerprintScan}
                        className={`p-10 rounded-full border-4 transition-all duration-300 relative z-10 overflow-hidden touch-none ${
                            isScanning 
                                ? 'bg-blue-600 text-white scale-110 border-blue-400 shadow-[0_0_60px_rgba(37,99,235,0.8)]' 
                                : 'bg-white/5 text-gray-400 border-white/10 hover:border-white/20 active:scale-95'
                        }`}
                        style={{ WebkitTapHighlightColor: 'transparent' }}
                    >
                        <FingerprintIcon className={`w-14 h-14 ${isScanning ? 'animate-pulse' : ''}`} />

                        {/* Scanning Laser Line */}
                        {isScanning && (
                            <div className="absolute inset-0 z-30 pointer-events-none overflow-hidden">
                                <div className="w-full h-1 bg-blue-300 shadow-[0_0_15px_rgba(147,197,253,1)] absolute top-0 left-0 animate-[laser_1s_infinite_linear]" />
                            </div>
                        )}

                        {/* Success Checkmark */}
                        {success && (
                             <div className="absolute inset-0 bg-green-500 flex items-center justify-center z-40 animate-[in_0.3s_ease-out]">
                                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={4} stroke="currentColor" className="w-16 h-16 text-white">
                                    <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
                                </svg>
                             </div>
                        )}
                    </button>

                    {isFingerprintSetup && !isScanning && !success && (
                        <div className="mt-12 flex flex-col items-center gap-2 animate-bounce">
                             <div className="w-px h-10 bg-gradient-to-t from-blue-500 to-transparent" />
                             <p className="text-blue-500 text-[10px] font-bold tracking-[0.2em]">TOUCH HERE</p>
                        </div>
                    )}
                </div>
            )}
        </div>
      </div>

      <style>{`
        @keyframes laser {
          0% { transform: translateY(-20px); opacity: 0; }
          10% { opacity: 1; }
          90% { opacity: 1; }
          100% { transform: translateY(140px); opacity: 0; }
        }
        @keyframes in {
          0% { transform: scale(0); border-radius: 100%; }
          100% { transform: scale(1); border-radius: 0%; }
        }
      `}</style>
    </div>
  );
};

