const UrlIcon: React.FC<{ src: string; name: string; className?: string }> = ({ src, name, className }) => {
  const [hasError, setHasError] = useState(false);

  useEffect(() => {
    setHasError(false);
  }, [src]);

  if (hasError || !src) {
    return <LinkIcon className={className} />;
  }

  return (
    <img 
      src={src} 
      alt={name} 
      className={`${className} object-cover rounded-md`} 
      onError={() => setHasError(true)}
    />
  );
};

export default function App() {
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditMode, setIsEditMode] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isLockSetupOpen, setIsLockSetupOpen] = useState(false);
  const [isFingerprintSetupOpen, setIsFingerprintSetupOpen] = useState(false);

  // Initialize settings first so it's available for other state initializers if needed
  const [settings, setSettings] = useState<LauncherSettings>(() => {
    try {
      const stored = localStorage.getItem(SETTINGS_KEY);
      const defaults = { passwordEnabled: false, passwordHash: '', fingerprintEnabled: false };
      return stored ? { ...defaults, ...JSON.parse(stored) } : defaults;
    } catch (e) {
      return { passwordEnabled: false, passwordHash: '', fingerprintEnabled: false };
    }
  });

  // Initialize lock state based on settings
  const [isLocked, setIsLocked] = useState(() => {
    return !!(settings.passwordEnabled && settings.passwordHash);
  });

  const [customApps, setCustomApps] = useState<StoredApp[]>([]);
  const [editingApp, setEditingApp] = useState<StoredApp | null>(null);

  const loadApps = () => {
    try {
      const stored = localStorage.getItem(LOCAL_STORAGE_KEY);
      if (stored) {
        const parsed = JSON.parse(stored);
        if (Array.isArray(parsed)) setCustomApps(parsed);
      }
    } catch (error) {
      console.error("Failed to load apps", error);
    }
  };

  useEffect(() => {
    loadApps();
  }, []);

  const saveApps = (newApps: StoredApp[]) => {
    setCustomApps(newApps);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(newApps));
  };

  const saveSettings = (newSettings: LauncherSettings) => {
    setSettings(newSettings);
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(newSettings));
  };

  const handleSaveApp = (app: StoredApp) => {
    let newApps;
    if (editingApp) {
      newApps = customApps.map(a => a.id === app.id ? app : a);
    } else {
      newApps = [...customApps, app];
    }
    saveApps(newApps);
    setIsModalOpen(false);
    setEditingApp(null);
  };

  const handleDeleteApp = (id: string) => {
    if (confirm('Are you sure you want to delete this app?')) {
      const newApps = customApps.filter(app => app.id !== id);
      saveApps(newApps);
    }
  };

  const handleUnlockAttempt = (attempt: string): boolean => {
    // Biometric bypass
    if (attempt === 'biometric') {
      // We trust the LockScreen component to only send 'biometric' if authorized
      setIsLocked(false);
      return true;
    }

    const hashedAttempt = btoa(attempt);
    if (hashedAttempt === settings.passwordHash) {
      setIsLocked(false);
      return true;
    }
    return false;
  };

  const handleSetPasscode = (passcode: string): boolean => {
    if (passcode.length < 4) return false;
    const hashed = btoa(passcode);
    saveSettings({
        ...settings,
        passwordEnabled: true,
        passwordHash: hashed
    });
    setIsLockSetupOpen(false);
    return true;
  };

  const handleCompleteFingerprintEnrollment = (type: string): boolean => {
    if (type === 'biometric') {
        saveSettings({
            ...settings,
            fingerprintEnabled: true
        });
        setIsFingerprintSetupOpen(false);
        return true;
    }
    return false;
  };

  const togglePasswordFeature = () => {
    if (settings.passwordEnabled) {
        if (confirm('Disable PIN protection and Fingerprint?')) {
            saveSettings({
                ...settings,
                passwordEnabled: false,
                passwordHash: '',
                fingerprintEnabled: false
            });
        }
    } else {
        setIsLockSetupOpen(true);
    }
  };

  const toggleFingerprintFeature = () => {
    if (settings.fingerprintEnabled) {
        saveSettings({
            ...settings,
            fingerprintEnabled: false
        });
    } else {
        setIsFingerprintSetupOpen(true);
    }
  };

  const defaultApps: AppItem[] = [
    {
      id: 'chrome',
      name: 'Chrome',
      icon: BrowserIcon,
      color: '#2563eb',
      action: () => window.open('https://www.google.com', '_blank'),
      isCustom: false
    },
    {
      id: 'roblox',
      name: 'Roblox',
      icon: GameIcon,
      color: '#ef4444',
      action: () => window.open('https://www.roblox.com', '_blank'),
      isCustom: false
    },
    {
      id: 'minecraft',
      name: 'Minecraft',
      icon: GameIcon,
      color: '#10b981',
      action: () => window.open('https://www.minecraft.net', '_blank'),
      isCustom: false
    },
    {
      id: 'playstore',
      name: 'Google Play',
      icon: PlayStoreIcon,
      color: '#0ea5e9',
      action: () => window.open('https://play.google.com', '_blank'),
      isCustom: false
    },
    {
      id: 'colab',
      name: 'Google Colab',
      icon: CodeIcon,
      color: '#f97316',
      action: () => window.open('https://colab.research.google.com/', '_blank'),
      isCustom: false
    },
    {
      id: 'photos',
      name: 'Photos',
      icon: PhotosIcon,
      color: '#ec4899',
      action: () => window.open('https://photos.google.com', '_blank'),
      isCustom: false
    },
    {
        id: 'launcher-settings',
        name: 'Launcher Settings',
        icon: SettingsIcon,
        color: '#475569',
        action: () => setIsSettingsOpen(true),
        isCustom: false
    }
  ];

  const mappedCustomApps: AppItem[] = customApps.map(app => {
    let IconComponent = LinkIcon;
    if (app.iconIdentifier && iconMap[app.iconIdentifier]) {
        IconComponent = iconMap[app.iconIdentifier];
    } else if (app.iconIdentifier && app.iconIdentifier.startsWith('http')) {
        IconComponent = ({ className }) => <UrlIcon src={app.iconIdentifier} name={app.name} className={className} />;
    }

    return {
        id: app.id,
        name: app.name,
        icon: IconComponent,
        color: app.color,
        action: () => window.open(app.url, '_blank'),
        isCustom: true
    };
  });

  const allApps = [...defaultApps, ...mappedCustomApps];

  const filteredApps = allApps.filter(app => 
    app.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-gray-900 p-6 md:p-12 font-sans selection:bg-blue-500/30 overflow-x-hidden relative">
        {/* Background blobs for depth */}
        <div className="fixed top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/10 blur-[120px] rounded-full pointer-events-none animate-pulse-bg" />
        <div className="fixed bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full pointer-events-none animate-pulse-bg animation-delay-4000" />

        {/* Lock Screen Overlay */}
        {isLocked && (
          <LockScreen 
            onUnlock={handleUnlockAttempt} 
            fingerprintEnabled={settings.fingerprintEnabled}
          />
        )}

        {/* PIN Setup Overlay */}
        {isLockSetupOpen && <LockScreen onUnlock={handleSetPasscode} isSetup={true} />}

        {/* Fingerprint Setup Overlay */}
        {isFingerprintSetupOpen && (
            <LockScreen 
                onUnlock={handleCompleteFingerprintEnrollment} 
                isFingerprintSetup={true} 
            />
        )}

        <div className="max-w-7xl mx-auto space-y-12 relative z-10">
            <Header 
                isEditMode={isEditMode} 
                onToggleEditMode={() => setIsEditMode(!isEditMode)}
                hasCustomApps={customApps.length > 0}
                onReload={loadApps}
                onLock={settings.passwordEnabled ? () => setIsLocked(true) : undefined}
            />

            <div className="space-y-8">
                <Clock />
                <SearchBar value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4 sm:gap-6">
                {filteredApps.map(app => (
                    <AppCard 
                        key={app.id} 
                        app={app} 
                        isEditMode={isEditMode}
                        onEdit={() => {
                            const stored = customApps.find(a => a.id === app.id);
                            if (stored) {
                                setEditingApp(stored);
                                setIsModalOpen(true);
                            }
                        }}
                        onDelete={() => handleDeleteApp(app.id)}
                    />
                ))}

                <button
                    onClick={() => { setEditingApp(null); setIsModalOpen(true); }}
                    className="aspect-square flex flex-col items-center justify-center p-4 rounded-2xl border-2 border-dashed border-gray-700 text-gray-500 hover:text-white hover:border-gray-500 hover:bg-gray-800/30 transition-all duration-300 group"
                >
                    <div className="p-4 rounded-full bg-gray-800 group-hover:bg-gray-700 transition-colors mb-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                        </svg>
                    </div>
                    <span className="text-sm font-medium">Add App</span>
                </button>
            </div>
        </div>

        <AddAppModal 
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            onSave={handleSaveApp}
            appToEdit={editingApp}
        />

        <SettingsModal 
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            isEditMode={isEditMode}
            onToggleEditMode={() => setIsEditMode(!isEditMode)}
            passwordEnabled={settings.passwordEnabled}
            onManagePassword={togglePasswordFeature}
            onLock={() => { setIsSettingsOpen(false); setIsLocked(true); }}
            fingerprintEnabled={settings.fingerprintEnabled}
            onToggleFingerprint={toggleFingerprintFeature}
        />
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import Clock from './Clock';
import { LockIcon, ShieldCheckIcon, FingerprintIcon } from './Icons';

interface LockScreenProps {
  onUnlock: (password: string) => boolean;
  isSetup?: boolean;
  isFingerprintSetup?: boolean;
  fingerprintEnabled?: boolean;
}

const LockScreen: React.FC<LockScreenProps> = ({ onUnlock, isSetup, isFingerprintSetup, fingerprintEnabled }) => {
  const [input, setInput] = useState('');
  const [error, setError] = useState(false);
  const [success, setSuccess] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scanProgress, setScanProgress] = useState(0);
  const [showHoldHint, setShowHoldHint] = useState(false);
  const [ready, setReady] = useState(false);

  const scanTimerRef = useRef<number | null>(null);
  const hintTimerRef = useRef<number | null>(null);

  // Small delay on mount to ensure pointer capture works correctly
  useEffect(() => {
    const t = setTimeout(() => setReady(true), 100);
    return () => clearTimeout(t);
  }, []);

  const handleKeypad = (num: string) => {
    if (input.length < 8) {
      setInput(prev => prev + num);
      setError(false);
    }
  };

  const handleBackspace = () => {
    setInput(prev => prev.slice(0, -1));
    setError(false);
  };

  const handleUnlock = () => {
    const isValid = onUnlock(input);
    if (isValid) {
      setSuccess(true);
    } else {
      setError(true);
      setTimeout(() => setInput(''), 300);
    }
  };

  const stopFingerprintScan = (e?: React.PointerEvent) => {
    if (e) {
      try { (e.currentTarget as HTMLElement).releasePointerCapture(e.pointerId); } catch(err) {}
    }

    if (scanTimerRef.current) {
      clearInterval(scanTimerRef.current);
      scanTimerRef.current = null;
    }

    // If they let go before finishing
    if (scanProgress > 0 && scanProgress < 100) {
        setShowHoldHint(true);
        if (hintTimerRef.current) clearTimeout(hintTimerRef.current);
        hintTimerRef.current = window.setTimeout(() => setShowHoldHint(false), 2000);
    }

    if (!success) {
      setIsScanning(false);
      setScanProgress(0);
      if (window.navigator.vibrate) window.navigator.vibrate(0); 
    }
  };

  const startFingerprintScan = (e: React.PointerEvent) => {
    if (!ready || isScanning || success) return;

    // Capture the pointer to follow it even if it moves outside the button
    try { (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId); } catch(err) {}

    setIsScanning(true);
    setError(false);
    setShowHoldHint(false);
    setScanProgress(0);

    if (window.navigator.vibrate) {
        window.navigator.vibrate([80, 40, 80]);
    }

    const duration = isFingerprintSetup ? 1200 : 800; // Snappier feel
    const interval = 16;
    const steps = duration / interval;
    let currentStep = 0;

    scanTimerRef.current = window.setInterval(() => {
        currentStep++;
        const progress = Math.min((currentStep / steps) * 100, 100);
        setScanProgress(progress);

        if (currentStep % 12 === 0 && window.navigator.vibrate) {
            window.navigator.vibrate(15);
        }

        if (currentStep >= steps) {
            if (scanTimerRef.current) clearInterval(scanTimerRef.current);
            scanTimerRef.current = null;

            if (window.navigator.vibrate) window.navigator.vibrate(100);

            const isValid = onUnlock('biometric');
            if (isValid) {
                setSuccess(true);
            } else {
                setError(true);
                setIsScanning(false);
                setScanProgress(0);
            }
        }
    }, interval);
  };

  useEffect(() => {
    return () => {
      if (scanTimerRef.current) clearInterval(scanTimerRef.current);
      if (hintTimerRef.current) clearTimeout(hintTimerRef.current);
    };
  }, []);

  const getStatusText = () => {
    if (success) return isFingerprintSetup ? 'Registered!' : 'Authorized';
    if (error) return 'Auth Failed. Try PIN.';
    if (isScanning) return 'Hold Still...';
    if (showHoldHint) return 'HOLD LONGER';
    if (isFingerprintSetup) return 'Touch & Hold Finger';
    if (isSetup) return 'Set Security PIN';
    return 'Secure Access Only';
  };

  return (
    <div className="fixed inset-0 z-[110] bg-gray-950/98 backdrop-blur-3xl flex flex-col items-center justify-center p-4 select-none touch-none overflow-hidden">
      {/* Dynamic background glow */}
      <div className={`absolute inset-0 transition-opacity duration-1000 ${isScanning ? 'opacity-20' : 'opacity-0'} bg-blue-600 blur-[100px] pointer-events-none`} />

      <div className={`mb-8 transition-all duration-700 ${isFingerprintSetup ? 'scale-75 opacity-20 blur-md translate-y-[-50%]' : 'scale-100'}`}>
        <Clock />
      </div>

      <div className={`w-full max-w-[320px] flex flex-col items-center space-y-8 transition-all duration-500 ${error ? 'animate-wiggle' : ''} ${success ? 'scale-150 opacity-0 pointer-events-none' : 'opacity-100'}`}>
        <div className="flex flex-col items-center gap-3">
          <div className={`p-4 rounded-3xl transition-all duration-500 ${isScanning ? 'bg-blue-600 shadow-[0_0_40px_rgba(37,99,235,0.6)] scale-110' : 'bg-white/5 border border-white/10'} text-white`}>
            {isSetup ? <ShieldCheckIcon className="w-8 h-8" /> : (isFingerprintSetup || fingerprintEnabled) ? <FingerprintIcon className="w-8 h-8" /> : <LockIcon className="w-8 h-8" />}
          </div>
          <div className="text-center">
            <h2 className="text-2xl font-black text-white tracking-widest uppercase">
              {isFingerprintSetup ? 'Biometrics' : isSetup ? 'PIN Security' : 'Plus+ Guard'}
            </h2>
            <p className={`mt-1 transition-all duration-300 h-4 ${isScanning || showHoldHint ? 'text-blue-400 font-bold' : 'text-gray-500'} text-[10px] tracking-[0.3em] uppercase`}>
              {getStatusText()}
            </p>
          </div>
        </div>

        {!isFingerprintSetup && (
            <div className={`flex justify-center gap-4 h-10 transition-opacity duration-300 ${isScanning ? 'opacity-10' : 'opacity-100'}`}>
                {Array.from({ length: Math.max(input.length, 4) }).map((_, i) => (
                    <div 
                        key={i} 
                        className={`w-3.5 h-3.5 rounded-full border-2 transition-all duration-300 ${
                            i < input.length 
                                ? 'bg-blue-500 border-blue-500 scale-125 shadow-[0_0_15px_rgba(59,130,246,0.6)]' 
                                : 'border-white/10 bg-transparent'
                        }`} 
                    />
                ))}
            </div>
        )}

        <div className="flex flex-col items-center gap-10 w-full">
            {!isFingerprintSetup && (
                <div className={`grid grid-cols-3 gap-4 w-full max-w-[260px] transition-all duration-700 ${isScanning ? 'opacity-0 scale-90 blur-sm pointer-events-none' : 'opacity-100'}`}>
                    {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                        <button
                            key={num}
                            type="button"
                            onClick={() => handleKeypad(num.toString())}
                            className="aspect-square rounded-3xl bg-white/5 hover:bg-white/10 text-white text-2xl font-bold transition-all border border-white/5 flex items-center justify-center active:scale-90 active:bg-blue-600/30"
                        >
                            {num}
                        </button>
                    ))}
                    <button 
                        type="button"
                        onClick={handleBackspace} 
                        className="aspect-square flex items-center justify-center text-white/30 hover:text-white transition-colors active:scale-90"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-7 h-7">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M12 9.75L14.25 12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12L12 14.25m-2.58 4.92l-6.37-6.37a2.25 2.25 0 010-3.18l6.37-6.37A2.25 2.25 0 0110.47 2.25h10.28c1.242 0 2.25 1.008 2.25 2.25v15a2.25 2.25 0 01-2.25 2.25H10.47a2.25 2.25 0 01-1.47-.58z" />
                        </svg>
                    </button>
                    <button
                        type="button"
                        onClick={() => handleKeypad('0')}
                        className="aspect-square rounded-3xl bg-white/5 hover:bg-white/10 text-white text-2xl font-bold transition-all border border-white/5 flex items-center justify-center active:scale-90 active:bg-blue-600/30"
                    >
                        0
                    </button>
                    <button 
                        type="button"
                        onClick={handleUnlock} 
                        disabled={input.length < 4}
                        className="aspect-square flex items-center justify-center rounded-3xl bg-blue-600 text-white transition-all shadow-[0_0_30px_rgba(37,99,235,0.4)] active:scale-95 disabled:opacity-10 disabled:grayscale disabled:shadow-none"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-7 h-7">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                        </svg>
                    </button>
                </div>
            )}

            {(isFingerprintSetup || (!isSetup && fingerprintEnabled)) && (
                <div className="relative flex flex-col items-center">
                    {/* Ring background */}
                    <div className="absolute inset-[-24px] rounded-full border-[6px] border-white/5 pointer-events-none" />

                    {/* Progress Ring */}
                    <svg className="absolute inset-[-24px] w-[calc(100%+48px)] h-[calc(100%+48px)] -rotate-90 pointer-events-none z-20">
                        <circle
                            cx="50%"
                            cy="50%"
                            r="54"
                            className={`transition-all duration-150 fill-none ${isScanning ? 'stroke-blue-400' : 'stroke-white/5'}`}
                            strokeWidth="10"
                            strokeDasharray="339.3"
                            strokeDashoffset={339.3 - (339.3 * scanProgress) / 100}
                            strokeLinecap="round"
                        />
                    </svg>

                    {/* Interaction Button */}
                    <button
                        type="button"
                        onPointerDown={startFingerprintScan}
                        onPointerUp={stopFingerprintScan}
                        onPointerLeave={stopFingerprintScan}
                        onPointerCancel={stopFingerprintScan}
                        onContextMenu={(e) => e.preventDefault()}
                        className={`p-12 rounded-full border-4 transition-all duration-300 relative z-10 overflow-hidden touch-none ${
                            isScanning 
                                ? 'bg-blue-600 text-white scale-110 border-blue-300 shadow-[0_0_80px_rgba(37,99,235,0.7)]' 
                                : 'bg-white/5 text-white/20 border-white/5 hover:border-white/10 active:scale-95'
                        }`}
                        style={{ WebkitTapHighlightColor: 'transparent' }}
                    >
                        <FingerprintIcon className={`w-16 h-16 ${isScanning ? 'animate-pulse' : ''}`} />

                        {/* Scanning Laser Line */}
                        {isScanning && (
                            <div className="absolute inset-0 z-30 pointer-events-none overflow-hidden">
                                <div className="w-full h-1.5 bg-blue-100 shadow-[0_0_20px_rgba(255,255,255,1)] absolute top-0 left-0 animate-[laser_0.8s_infinite_linear]" />
                            </div>
                        )}

                        {/* Status Glow Overlay */}
                        {success && (
                             <div className="absolute inset-0 bg-green-500 flex items-center justify-center z-40 animate-[reveal_0.4s_ease-out_fill]">
                                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={5} stroke="currentColor" className="w-20 h-20 text-white">
                                    <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
                                </svg>
                             </div>
                        )}
                    </button>

                    {isFingerprintSetup && !isScanning && !success && (
                        <div className="mt-14 flex flex-col items-center gap-3 animate-bounce">
                             <div className="w-0.5 h-12 bg-gradient-to-t from-blue-500 to-transparent" />
                             <p className="text-blue-500 text-[9px] font-black tracking-[0.4em]">TOUCH & HOLD SENSOR</p>
                        </div>
                    )}
                </div>
            )}
        </div>
      </div>

      <style>{`
        @keyframes laser {
          0% { transform: translateY(-30px); opacity: 0; }
          20% { opacity: 1; }
          80% { opacity: 1; }
          100% { transform: translateY(160px); opacity: 0; }
        }
        @keyframes reveal {
          0% { opacity: 0; transform: scale(0.5); }
          100% { opacity: 1; transform: scale(1); }
        }
      `}</style>
    </div>
  );
};

