        if (hintTimerRef.current) clearTimeout(hintTimerRef.current);
        hintTimerRef.current = window.setTimeout(() => setShowHoldHint(false), 2000);
    }

    if (!success) {
      setIsScanning(false);
      setScanProgress(0);
      if (window.navigator.vibrate) window.navigator.vibrate(0); 
    }
  };

  const startFingerprintScan = (e: React.PointerEvent) => {
    if (!ready || isScanning || success) return;

    // Capture the pointer to follow it even if it moves outside the button
    try { (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId); } catch(err) {}

    setIsScanning(true);
    setError(false);
    setShowHoldHint(false);
    setScanProgress(0);

    if (window.navigator.vibrate) {
        window.navigator.vibrate([80, 40, 80]);
    }

    const duration = isFingerprintSetup ? 1200 : 800; // Snappier feel
    const interval = 16;
    const steps = duration / interval;
    let currentStep = 0;

    scanTimerRef.current = window.setInterval(() => {
        currentStep++;
        const progress = Math.min((currentStep / steps) * 100, 100);
        setScanProgress(progress);

        if (currentStep % 12 === 0 && window.navigator.vibrate) {
            window.navigator.vibrate(15);
        }

        if (currentStep >= steps) {
            if (scanTimerRef.current) clearInterval(scanTimerRef.current);
            scanTimerRef.current = null;

            if (window.navigator.vibrate) window.navigator.vibrate(100);

            const isValid = onUnlock('biometric');
            if (isValid) {
                setSuccess(true);
            } else {
                setError(true);
                setIsScanning(false);
                setScanProgress(0);
            }
        }
    }, interval);
  };

  useEffect(() => {
    return () => {
      if (scanTimerRef.current) clearInterval(scanTimerRef.current);
      if (hintTimerRef.current) clearTimeout(hintTimerRef.current);
    };
  }, []);

  const getStatusText = () => {
    if (success) return isFingerprintSetup ? 'Registered!' : 'Authorized';
    if (error) return 'Auth Failed. Try PIN.';
    if (isScanning) return 'Hold Still...';
    if (showHoldHint) return 'HOLD LONGER';
    if (isFingerprintSetup) return 'Touch & Hold Finger';
    if (isSetup) return 'Set Security PIN';
    return 'Secure Access Only';
  };

  return (
    <div className="fixed inset-0 z-[110] bg-gray-950/98 backdrop-blur-3xl flex flex-col items-center justify-center p-4 select-none touch-none overflow-hidden">
      {/* Dynamic background glow */}
      <div className={`absolute inset-0 transition-opacity duration-1000 ${isScanning ? 'opacity-20' : 'opacity-0'} bg-blue-600 blur-[100px] pointer-events-none`} />

      <div className={`mb-4 sm:mb-8 transition-all duration-700 ${isFingerprintSetup ? 'scale-75 opacity-20 blur-md translate-y-[-50%]' : 'scale-90 sm:scale-100'}`}>
        <Clock />
      </div>

      <div className={`w-full max-w-[320px] flex flex-col items-center space-y-4 sm:space-y-8 transition-all duration-500 ${error ? 'animate-wiggle' : ''} ${success ? 'scale-150 opacity-0 pointer-events-none' : 'opacity-100'}`}>
        <div className="flex flex-col items-center gap-2">
          <div className={`p-3 sm:p-4 rounded-2xl sm:rounded-3xl transition-all duration-500 ${isScanning ? 'bg-blue-600 shadow-[0_0_40px_rgba(37,99,235,0.6)] scale-110' : 'bg-white/5 border border-white/10'} text-white`}>
            {isSetup ? <ShieldCheckIcon className="w-6 h-6 sm:w-8 sm:h-8" /> : (isFingerprintSetup || fingerprintEnabled) ? <FingerprintIcon className="w-6 h-6 sm:w-8 sm:h-8" /> : <LockIcon className="w-6 h-6 sm:w-8 sm:h-8" />}
          </div>
          <div className="text-center">
            <h2 className="text-lg sm:text-2xl font-black text-white tracking-widest uppercase">
              {isFingerprintSetup ? 'Biometrics' : isSetup ? 'PIN Security' : 'Plus+ Guard'}
            </h2>
            <p className={`mt-0.5 transition-all duration-300 h-4 ${isScanning || showHoldHint ? 'text-blue-400 font-bold' : 'text-gray-500'} text-[8px] sm:text-[10px] tracking-[0.3em] uppercase`}>
              {getStatusText()}
            </p>
          </div>
        </div>

        {!isFingerprintSetup && (
            <div className={`flex justify-center gap-3 sm:gap-4 h-6 sm:h-10 transition-opacity duration-300 ${isScanning ? 'opacity-10' : 'opacity-100'}`}>
                {Array.from({ length: Math.max(input.length, 4) }).map((_, i) => (
                    <div 
                        key={i} 
                        className={`w-2.5 h-2.5 sm:w-3.5 sm:h-3.5 rounded-full border-2 transition-all duration-300 ${
                            i < input.length 
                                ? 'bg-blue-500 border-blue-500 scale-125 shadow-[0_0_15px_rgba(59,130,246,0.6)]' 
                                : 'border-white/10 bg-transparent'
                        }`} 
                    />
                ))}
            </div>
        )}

        <div className="flex flex-col items-center gap-4 sm:gap-10 w-full">
            {!isFingerprintSetup && (
                <div className={`grid grid-cols-3 gap-2 sm:gap-4 w-full max-w-[200px] sm:max-w-[260px] transition-all duration-700 ${isScanning ? 'opacity-0 scale-90 blur-sm pointer-events-none' : 'opacity-100'}`}>
                    {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                        <button
                            key={num}
                            type="button"
                            onClick={() => handleKeypad(num.toString())}
                            className="aspect-square rounded-2xl bg-white/5 hover:bg-white/10 text-white text-xl sm:text-2xl font-bold transition-all border border-white/5 flex items-center justify-center active:scale-90 active:bg-blue-600/30"
                        >
                            {num}
                        </button>
                    ))}
                    <button 
                        type="button"
                        onClick={handleBackspace} 
                        className="aspect-square flex items-center justify-center text-white/30 hover:text-white transition-colors active:scale-90"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-6 h-6 sm:w-7 sm:h-7">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M12 9.75L14.25 12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12L12 14.25m-2.58 4.92l-6.37-6.37a2.25 2.25 0 010-3.18l6.37-6.37A2.25 2.25 0 0110.47 2.25h10.28c1.242 0 2.25 1.008 2.25 2.25v15a2.25 2.25 0 01-2.25 2.25H10.47a2.25 2.25 0 01-1.47-.58z" />
                        </svg>
                    </button>
                    <button
                        type="button"
                        onClick={() => handleKeypad('0')}
                        className="aspect-square rounded-2xl bg-white/5 hover:bg-white/10 text-white text-xl sm:text-2xl font-bold transition-all border border-white/5 flex items-center justify-center active:scale-90 active:bg-blue-600/30"
                    >
                        0
                    </button>
                    <button 
                        type="button"
                        onClick={handleUnlock} 
                        disabled={input.length < 4}
                        className="aspect-square flex items-center justify-center rounded-2xl bg-blue-600 text-white transition-all shadow-[0_0_30px_rgba(37,99,235,0.4)] active:scale-95 disabled:opacity-10 disabled:grayscale disabled:shadow-none"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-6 h-6 sm:w-7 sm:h-7">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                        </svg>
                    </button>
                </div>
            )}

            {(isFingerprintSetup || (!isSetup && fingerprintEnabled)) && (
                <div className="relative flex flex-col items-center">
                    {/* Ring background */}
                    <div className="absolute inset-[-18px] sm:inset-[-24px] rounded-full border-[4px] sm:border-[6px] border-white/5 pointer-events-none" />

                    {/* Progress Ring */}
                    <svg className="absolute inset-[-18px] sm:inset-[-24px] w-[calc(100%+36px)] sm:w-[calc(100%+48px)] h-[calc(100%+36px)] sm:h-[calc(100%+48px)] -rotate-90 pointer-events-none z-20">
                        <circle
                            cx="50%"
                            cy="50%"
                            r="42"
                            className={`transition-all duration-150 fill-none ${isScanning ? 'stroke-blue-400' : 'stroke-white/5'}`}
                            strokeWidth="8"
                            strokeDasharray="263.8"
                            strokeDashoffset={263.8 - (263.8 * scanProgress) / 100}
                            strokeLinecap="round"
                        />
                    </svg>

                    {/* Interaction Button */}
                    <button
                        type="button"
                        onPointerDown={startFingerprintScan}
                        onPointerUp={stopFingerprintScan}
                        onPointerLeave={stopFingerprintScan}
                        onPointerCancel={stopFingerprintScan}
                        onContextMenu={(e) => e.preventDefault()}
                        className={`p-10 sm:p-12 rounded-full border-4 transition-all duration-300 relative z-10 overflow-hidden touch-none ${
                            isScanning 
                                ? 'bg-blue-600 text-white scale-110 border-blue-300 shadow-[0_0_80px_rgba(37,99,235,0.7)]' 
                                : 'bg-white/5 text-white/20 border-white/5 hover:border-white/10 active:scale-95'
                        }`}
                        style={{ WebkitTapHighlightColor: 'transparent' }}
                    >
                        <FingerprintIcon className={`w-12 h-12 sm:w-16 sm:h-16 ${isScanning ? 'animate-pulse' : ''}`} />

                        {/* Scanning Laser Line */}
                        {isScanning && (
                            <div className="absolute inset-0 z-30 pointer-events-none overflow-hidden">
                                <div className="w-full h-1.5 bg-blue-100 shadow-[0_0_20px_rgba(255,255,255,1)] absolute top-0 left-0 animate-[laser_0.8s_infinite_linear]" />
                            </div>
                        )}

                        {/* Status Glow Overlay */}
                        {success && (
                             <div className="absolute inset-0 bg-green-500 flex items-center justify-center z-40 animate-[reveal_0.4s_ease-out_fill]">
                                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={5} stroke="currentColor" className="w-16 h-16 sm:w-20 sm:h-20 text-white">
                                    <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
                                </svg>
                             </div>
                        )}
                    </button>

                    {isFingerprintSetup && !isScanning && !success && (
                        <div className="mt-8 sm:mt-14 flex flex-col items-center gap-2 sm:gap-3 animate-bounce">
                             <div className="w-0.5 h-8 sm:h-12 bg-gradient-to-t from-blue-500 to-transparent" />
                             <p className="text-blue-500 text-[8px] sm:text-[9px] font-black tracking-[0.4em]">TOUCH & HOLD SENSOR</p>
                        </div>
                    )}
                </div>
            )}
        </div>
      </div>

      <style>{`
        @keyframes laser {
          0% { transform: translateY(-30px); opacity: 0; }
          20% { opacity: 1; }
          80% { opacity: 1; }
          100% { transform: translateY(160px); opacity: 0; }
        }
        @keyframes reveal {
          0% { opacity: 0; transform: scale(0.5); }
          100% { opacity: 1; transform: scale(1); }
        }
      `}</style>
    </div>
  );
};

export default LockScreen;

import React, { useState, useEffect, useRef } from 'react';
import Clock from './Clock';
import { LockIcon, ShieldCheckIcon, FingerprintIcon } from './Icons';

interface LockScreenProps {
  onUnlock: (password: string) => boolean;
  isSetup?: boolean;
  isFingerprintSetup?: boolean;
  fingerprintEnabled?: boolean;
}

const LockScreen: React.FC<LockScreenProps> = ({ onUnlock, isSetup, isFingerprintSetup, fingerprintEnabled }) => {
  const [input, setInput] = useState('');
  const [error, setError] = useState(false);
  const [success, setSuccess] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [scanProgress, setScanProgress] = useState(0);
  const [showHoldHint, setShowHoldHint] = useState(false);
  const [ready, setReady] = useState(false);

  const scanTimerRef = useRef<number | null>(null);
  const hintTimerRef = useRef<number | null>(null);

  useEffect(() => {
    const t = setTimeout(() => setReady(true), 50);
    return () => clearTimeout(t);
  }, []);

  const handleKeypad = (num: string) => {
    if (input.length < 8) {
      setInput(prev => prev + num);
      setError(false);
    }
  };

  const handleBackspace = () => {
    setInput(prev => prev.slice(0, -1));
    setError(false);
  };

  const handleUnlock = () => {
    const isValid = onUnlock(input);
    if (isValid) {
      setSuccess(true);
    } else {
      setError(true);
      setTimeout(() => setInput(''), 300);
    }
  };

  const stopFingerprintScan = (e?: React.PointerEvent) => {
    if (e) {
      try { (e.currentTarget as HTMLElement).releasePointerCapture(e.pointerId); } catch(err) {}
    }

    if (scanTimerRef.current) {
      clearInterval(scanTimerRef.current);
      scanTimerRef.current = null;
    }

    if (scanProgress > 0 && scanProgress < 100) {
        setShowHoldHint(true);
        if (hintTimerRef.current) clearTimeout(hintTimerRef.current);
        hintTimerRef.current = window.setTimeout(() => setShowHoldHint(false), 1500);
    }

    if (!success) {
      setIsScanning(false);
      setScanProgress(0);
      if (window.navigator.vibrate) window.navigator.vibrate(0); 
    }
  };

  const startFingerprintScan = (e: React.PointerEvent) => {
    if (!ready || isScanning || success) return;
    try { (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId); } catch(err) {}

    setIsScanning(true);
    setError(false);
    setShowHoldHint(false);
    setScanProgress(0);

    if (window.navigator.vibrate) window.navigator.vibrate([60, 30, 60]);

    const duration = isFingerprintSetup ? 1000 : 700; 
    const interval = 16;
    const steps = duration / interval;
    let currentStep = 0;

    scanTimerRef.current = window.setInterval(() => {
        currentStep++;
        const progress = Math.min((currentStep / steps) * 100, 100);
        setScanProgress(progress);

        if (currentStep % 15 === 0 && window.navigator.vibrate) {
            window.navigator.vibrate(10);
        }

        if (currentStep >= steps) {
            if (scanTimerRef.current) clearInterval(scanTimerRef.current);
            scanTimerRef.current = null;
            if (window.navigator.vibrate) window.navigator.vibrate(80);

            if (onUnlock('biometric')) {
                setSuccess(true);
            } else {
                setError(true);
                setIsScanning(false);
                setScanProgress(0);
            }
        }
    }, interval);
  };

  useEffect(() => {
    return () => {
      if (scanTimerRef.current) clearInterval(scanTimerRef.current);
      if (hintTimerRef.current) clearTimeout(hintTimerRef.current);
    };
  }, []);

  const getStatusText = () => {
    if (success) return 'Success';
    if (error) return 'Mismatch';
    if (isScanning) return 'Wait...';
    if (showHoldHint) return 'Hold!';
    return isFingerprintSetup ? 'Enroll' : (isSetup ? 'New PIN' : 'Locked');
  };

  return (
    <div className="fixed inset-0 z-[110] bg-gray-950/98 backdrop-blur-3xl flex flex-col items-center justify-start py-4 px-2 select-none touch-none overflow-hidden">
      {/* Background Glow */}
      <div className={`absolute inset-0 transition-opacity duration-700 ${isScanning ? 'opacity-30' : 'opacity-0'} bg-blue-600/20 blur-[80px] pointer-events-none`} />

      {/* Extreme Shrunken Clock */}
      <div className={`transition-all duration-700 origin-top mb-1 ${isFingerprintSetup ? 'scale-[0.4] opacity-10 h-0 overflow-hidden' : 'scale-[0.5] sm:scale-75'}`}>
        <Clock />
      </div>

      <div className={`w-full max-w-[280px] flex flex-col items-center space-y-3 transition-all duration-500 ${error ? 'animate-wiggle' : ''} ${success ? 'scale-125 opacity-0 pointer-events-none' : 'opacity-100'}`}>

        {/* Compact Status Header */}
        <div className="flex flex-col items-center gap-1">
          <div className={`p-2 rounded-xl transition-all duration-300 ${isScanning ? 'bg-blue-600 shadow-[0_0_20px_rgba(37,99,235,0.5)] scale-110' : 'bg-white/5'} text-white`}>
            {isSetup ? <ShieldCheckIcon className="w-5 h-5" /> : (isFingerprintSetup || fingerprintEnabled) ? <FingerprintIcon className="w-5 h-5" /> : <LockIcon className="w-5 h-5" />}
          </div>
          <div className="text-center">
            <h2 className="text-sm font-black text-white tracking-[0.2em] uppercase">Plus+ Guard</h2>
            <p className={`transition-all duration-300 h-3 text-[9px] font-bold tracking-widest uppercase ${isScanning || showHoldHint ? 'text-blue-400' : 'text-gray-500'}`}>
              {getStatusText()}
            </p>
          </div>
        </div>

        {/* Shrunken PIN Indicators */}
        {!isFingerprintSetup && (
            <div className={`flex justify-center gap-2 h-4 transition-opacity duration-300 ${isScanning ? 'opacity-0' : 'opacity-100'}`}>
                {Array.from({ length: Math.max(input.length, 4) }).map((_, i) => (
                    <div 
                        key={i} 
                        className={`w-2 h-2 rounded-full border transition-all duration-200 ${
                            i < input.length ? 'bg-blue-500 border-blue-500 scale-110' : 'border-white/10 bg-transparent'
                        }`} 
                    />
                ))}
            </div>
        )}

        <div className="flex flex-col items-center gap-4 w-full">
            {/* Extremely Compact Keypad */}
            {!isFingerprintSetup && (
                <div className={`grid grid-cols-3 gap-2 w-full max-w-[180px] transition-all duration-500 ${isScanning ? 'opacity-0 scale-90 blur-md pointer-events-none' : 'opacity-100'}`}>
                    {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                        <button
                            key={num}
                            type="button"
                            onClick={() => handleKeypad(num.toString())}
                            className="aspect-square rounded-xl bg-white/5 hover:bg-white/10 text-white text-lg font-bold transition-all border border-white/5 flex items-center justify-center active:scale-90 active:bg-blue-600/20"
                        >
                            {num}
                        </button>
                    ))}
                    <button onClick={handleBackspace} className="aspect-square flex items-center justify-center text-white/30 hover:text-white active:scale-90">
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M12 9.75L14.25 12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12L12 14.25m-2.58 4.92l-6.37-6.37a2.25 2.25 0 010-3.18l6.37-6.37A2.25 2.25 0 0110.47 2.25h10.28c1.242 0 2.25 1.008 2.25 2.25v15a2.25 2.25 0 01-2.25 2.25H10.47a2.25 2.25 0 01-1.47-.58z" /></svg>
                    </button>
                    <button onClick={() => handleKeypad('0')} className="aspect-square rounded-xl bg-white/5 hover:bg-white/10 text-white text-lg font-bold border border-white/5 active:scale-90">0</button>
                    <button 
                        onClick={handleUnlock} 
                        disabled={input.length < 4}
                        className="aspect-square flex items-center justify-center rounded-xl bg-blue-600 text-white shadow-lg active:scale-95 disabled:opacity-10 disabled:grayscale"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" /></svg>
                    </button>
                </div>
            )}

            {/* Fingerprint Scanner Area */}
            {(isFingerprintSetup || (!isSetup && fingerprintEnabled)) && (
                <div className="relative flex flex-col items-center mt-2">
                    {/* Compact Ring */}
                    <div className="absolute inset-[-12px] rounded-full border-[3px] border-white/5 pointer-events-none" />
                    <svg className="absolute inset-[-12px] w-[calc(100%+24px)] h-[calc(100%+24px)] -rotate-90 pointer-events-none z-20">
                        <circle cx="50%" cy="50%" r="30" className={`fill-none ${isScanning ? 'stroke-blue-400' : 'stroke-white/5'}`} strokeWidth="6" strokeDasharray="188.5" strokeDashoffset={188.5 - (188.5 * scanProgress) / 100} strokeLinecap="round" />
                    </svg>

                    <button
                        onPointerDown={startFingerprintScan}
                        onPointerUp={stopFingerprintScan}
                        onPointerLeave={stopFingerprintScan}
                        onPointerCancel={stopFingerprintScan}
                        onContextMenu={(e) => e.preventDefault()}
                        className={`p-6 rounded-full border-2 transition-all duration-300 relative z-10 overflow-hidden touch-none ${
                            isScanning ? 'bg-blue-600 text-white scale-110 border-blue-300 shadow-xl' : 'bg-white/5 text-white/20 border-white/5'
                        }`}
                        style={{ WebkitTapHighlightColor: 'transparent' }}
                    >
                        <FingerprintIcon className={`w-10 h-10 ${isScanning ? 'animate-pulse' : ''}`} />
                        {isScanning && <div className="absolute inset-0 z-30 pointer-events-none overflow-hidden"><div className="w-full h-1 bg-blue-100 shadow-lg absolute top-0 left-0 animate-[laser_0.7s_infinite_linear]" /></div>}
                        {success && (
                             <div className="absolute inset-0 bg-green-500 flex items-center justify-center z-40 animate-[reveal_0.3s_ease-out_fill]">
                                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={5} stroke="currentColor" className="w-10 h-10 text-white"><path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" /></svg>
                             </div>
                        )}
                    </button>

                    {!isScanning && !success && (
                        <p className="mt-2 text-blue-500 text-[8px] font-black tracking-[0.2em] animate-pulse">HOLD</p>
                    )}
                </div>
            )}
        </div>
      </div>

      <style>{`
        @keyframes laser {
          0% { transform: translateY(-20px); opacity: 0; }
          20% { opacity: 1; }
          80% { opacity: 1; }
          100% { transform: translateY(100px); opacity: 0; }
        }
        @keyframes reveal {
          0% { opacity: 0; transform: scale(0.5); }
          100% { opacity: 1; transform: scale(1); }
        }
      `}</style>
    </div>
  );
};

export default LockScreen;

