import React, { useState, useEffect, useRef } from 'react';
import Clock from './Clock';
import { LockIcon, ShieldCheckIcon, FingerprintIcon, FaceIdIcon } from './Icons';
import { GoogleGenAI } from "@google/genai";

interface LockScreenProps {
  onUnlock: (password: string) => boolean;
  isSetup?: boolean;
  isFingerprintSetup?: boolean;
  isFaceIdSetup?: boolean;
  fingerprintEnabled?: boolean;
  faceIdEnabled?: boolean;
}

const LockScreen: React.FC<LockScreenProps> = ({ 
    onUnlock, isSetup, isFingerprintSetup, isFaceIdSetup, fingerprintEnabled, faceIdEnabled 
}) => {
  const [input, setInput] = useState('');
  const [error, setError] = useState(false);
  const [success, setSuccess] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const [scanProgress, setScanProgress] = useState(0);
  const [analysisText, setAnalysisText] = useState('SECURE');
  const [ready, setReady] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const scanTimerRef = useRef<number | null>(null);

  useEffect(() => {
    const t = setTimeout(() => setReady(true), 50);
    return () => clearTimeout(t);
  }, []);

  // Face ID Camera Stream
  useEffect(() => {
    if (isFaceIdSetup || faceIdEnabled) {
        navigator.mediaDevices.getUserMedia({ video: true })
            .then(stream => {
                if (videoRef.current) videoRef.current.srcObject = stream;
                if (faceIdEnabled && !isFaceIdSetup) {
                    // Short delay to let camera warm up before auto-scan
                    setTimeout(startFaceScan, 800);
                }
            })
            .catch(err => {
                console.error("Camera denied", err);
                setAnalysisText("CAM ERROR");
            });

        return () => {
            if (videoRef.current?.srcObject) {
                (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
            }
        };
    }
  }, [isFaceIdSetup, faceIdEnabled]);

  const verifyFaceWithAI = async (base64Image: string) => {
    setIsVerifying(true);
    setAnalysisText("AI VERIFYING...");

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: [
                {
                    parts: [
                        { text: "Analyze this camera frame for a security lock screen. Return exactly 'VALID' if you see a clear human face looking at the camera. Return 'INVALID' if the camera is blocked, too dark, or no face is visible. Be strict. Answer in one word." },
                        { inlineData: { mimeType: 'image/jpeg', data: base64Image } }
                    ]
                }
            ]
        });

        const result = response.text?.trim().toUpperCase();
        if (result === 'VALID') {
            setSuccess(true);
            onUnlock('faceid');
        } else {
            throw new Error("No face detected");
        }
    } catch (err) {
        setError(true);
        setAnalysisText("NO FACE FOUND");
        setIsVerifying(false);
        setIsScanning(false);
        setScanProgress(0);
        setTimeout(() => {
            setError(false);
            setAnalysisText("RETRY");
        }, 2000);
    }
  };

  const captureAndVerify = () => {
    if (!videoRef.current || !canvasRef.current) return;

    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const dataUrl = canvas.toDataURL('image/jpeg', 0.6);
    const base64 = dataUrl.split(',')[1];

    verifyFaceWithAI(base64);
  };

  const startFaceScan = () => {
    if (isScanning || isVerifying || success) return;
    setIsScanning(true);
    setScanProgress(0);
    setError(false);
    setAnalysisText("SCANNING...");

    let progress = 0;
    const interval = setInterval(() => {
        progress += 3;
        setScanProgress(Math.min(progress, 100));
        if (progress >= 100) {
            clearInterval(interval);
            captureAndVerify();
        }
    }, 30);
  };

  const handleKeypad = (num: string) => {
    if (input.length < 8) {
      setInput(prev => prev + num);
      setError(false);
    }
  };

  const handleBackspace = () => {
    setInput(prev => prev.slice(0, -1));
    setError(false);
  };

  const handleUnlock = () => {
    const isValid = onUnlock(input);
    if (isValid) setSuccess(true);
    else {
      setError(true);
      setTimeout(() => setInput(''), 300);
    }
  };

  const stopFingerprintScan = (e?: React.PointerEvent) => {
    if (e) try { (e.currentTarget as HTMLElement).releasePointerCapture(e.pointerId); } catch(err) {}
    if (scanTimerRef.current) clearInterval(scanTimerRef.current);
    if (!success) {
      setIsScanning(false);
      setScanProgress(0);
      setAnalysisText('HOLD');
    }
  };

  const startFingerprintScan = (e: React.PointerEvent) => {
    if (!ready || isScanning || success) return;
    try { (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId); } catch(err) {}
    setIsScanning(true);
    setScanProgress(0);
    setError(false);

    const analysisSteps = ["Sampling...", "Mapping", "Verifying"];
    const duration = isFingerprintSetup ? 1200 : 800;
    const steps = duration / 16;
    let currentStep = 0;

    scanTimerRef.current = window.setInterval(() => {
        currentStep++;
        const progress = Math.min((currentStep / steps) * 100, 100);
        setScanProgress(progress);

        const textIdx = Math.floor((progress / 100) * analysisSteps.length);
        setAnalysisText(analysisSteps[textIdx] || "Verifying");

        if (currentStep >= steps) {
            clearInterval(scanTimerRef.current!);
            if (onUnlock('biometric')) setSuccess(true);
            else { setError(true); setIsScanning(false); setScanProgress(0); }
        }
    }, 16);
  };

  return (
    <div className="fixed inset-0 z-[110] bg-gray-950/98 backdrop-blur-3xl flex flex-col items-center justify-start py-4 px-2 select-none touch-none overflow-hidden">
      <div className={`absolute inset-0 transition-opacity duration-700 ${isScanning || isVerifying ? 'opacity-30' : 'opacity-0'} ${error ? 'bg-red-600/20' : 'bg-blue-600/20'} blur-[80px] pointer-events-none`} />

      <canvas ref={canvasRef} className="hidden" />

      <div className={`transition-all duration-700 origin-top mb-1 ${isFingerprintSetup || isFaceIdSetup ? 'scale-[0.3] opacity-0 h-0' : 'scale-[0.4] sm:scale-60'}`}>
        <Clock />
      </div>

      <div className={`w-full max-w-[240px] flex flex-col items-center space-y-2 transition-all duration-500 ${error ? 'animate-wiggle' : ''} ${success ? 'scale-125 opacity-0 pointer-events-none' : 'opacity-100'}`}>

        {/* Guard Header */}
        <div className="flex flex-col items-center gap-0.5">
          <div className={`p-1.5 rounded-lg transition-all duration-300 ${success ? 'bg-green-600 shadow-[0_0_20px_rgba(34,197,94,0.5)]' : error ? 'bg-red-600' : isVerifying ? 'bg-amber-600 animate-pulse' : isScanning ? 'bg-blue-600' : 'bg-white/5'} text-white`}>
            {isSetup ? <ShieldCheckIcon className="w-4 h-4" /> : (isFaceIdSetup || faceIdEnabled) ? <FaceIdIcon className="w-4 h-4" /> : <FingerprintIcon className="w-4 h-4" />}
          </div>
          <div className="text-center">
            <h2 className="text-[10px] font-black text-white tracking-[0.1em] uppercase">Plus Guard</h2>
            <p className={`h-3 text-[8px] font-bold tracking-widest uppercase transition-colors ${success ? 'text-green-400' : error ? 'text-red-400' : isVerifying ? 'text-amber-400' : isScanning ? 'text-blue-400' : 'text-gray-500'}`}>
               {success ? 'Authorized' : analysisText}
            </p>
          </div>
        </div>

        {/* Face ID Viewbox */}
        {(isFaceIdSetup || faceIdEnabled) && (
            <div className={`relative w-28 h-28 rounded-full border-2 transition-colors duration-500 overflow-hidden bg-black mb-1 ${success ? 'border-green-500' : error ? 'border-red-500' : isVerifying ? 'border-amber-500' : 'border-white/10'}`}>
                <video ref={videoRef} autoPlay playsInline muted className={`w-full h-full object-cover transition-all duration-500 ${success ? 'grayscale-0 brightness-100' : 'grayscale brightness-125'}`} />

                {(isScanning || isVerifying) && (
                    <div className="absolute inset-0 z-10 pointer-events-none">
                        <div className={`w-full h-0.5 shadow-lg absolute top-0 left-0 animate-[face_1.5s_infinite_ease-in-out] ${isVerifying ? 'bg-amber-400 shadow-[0_0_15px_amber]' : 'bg-blue-400 shadow-[0_0_15px_blue]'}`} />
                        <div className={`absolute inset-4 border-2 rounded-full animate-pulse ${isVerifying ? 'border-amber-400/30' : 'border-blue-400/30'}`} />
                    </div>
                )}

                {isFaceIdSetup && !isScanning && !isVerifying && (
                    <button onClick={startFaceScan} className="absolute inset-0 bg-blue-600/80 text-white text-[10px] font-bold uppercase flex flex-col items-center justify-center gap-1">
                        <FaceIdIcon className="w-6 h-6" />
                        Enroll Face
                    </button>
                )}

                {faceIdEnabled && error && !isScanning && (
                    <button onClick={startFaceScan} className="absolute inset-0 bg-red-600/80 text-white text-[9px] font-bold uppercase flex items-center justify-center">Try Again</button>
                )}
            </div>
        )}

        {/* PIN Pad */}
        {!isFingerprintSetup && !isFaceIdSetup && !isScanning && !isVerifying && (
            <div className="flex flex-col items-center gap-2 w-full">
                <div className="flex justify-center gap-1.5 h-3">
                    {Array.from({ length: Math.max(input.length, 4) }).map((_, i) => (
                        <div key={i} className={`w-1.5 h-1.5 rounded-full border transition-all ${i < input.length ? 'bg-blue-500 border-blue-500 scale-110 shadow-[0_0_10px_rgba(59,130,246,0.5)]' : 'border-white/10 bg-transparent'}`} />
                    ))}
                </div>
                <div className="grid grid-cols-3 gap-1.5 w-full max-w-[150px]">
                    {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                        <button key={num} onClick={() => handleKeypad(num.toString())} className="aspect-square rounded-lg bg-white/5 text-white text-sm font-bold border border-white/5 active:bg-blue-600/30 transition-colors">{num}</button>
                    ))}
                    <button onClick={handleBackspace} className="aspect-square flex items-center justify-center text-white/20 active:text-white"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeWidth={2.5} d="M12 9.75L14.25 12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12L12 14.25m-2.58 4.92l-6.37-6.37a2.25 2.25 0 010-3.18l6.37-6.37A2.25 2.25 0 0110.47 2.25h10.28c1.242 0 2.25 1.008 2.25 2.25v15a2.25 2.25 0 01-2.25 2.25H10.47a2.25 2.25 0 01-1.47-.58z" /></svg></button>
                    <button onClick={() => handleKeypad('0')} className="aspect-square rounded-lg bg-white/5 text-white text-sm font-bold border border-white/5 active:bg-blue-600/30">0</button>
                    <button onClick={handleUnlock} disabled={input.length < 4} className="aspect-square flex items-center justify-center rounded-lg bg-blue-600 text-white active:scale-95 disabled:opacity-5 shadow-lg"><svg className="w-4 h-4" fill="none" stroke="currentColor" strokeWidth={3} viewBox="0 0 24 24"><path d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" /></svg></button>
                </div>
            </div>
        )}

        {/* Fingerprint Button */}
        {(isFingerprintSetup || fingerprintEnabled) && !isFaceIdSetup && !faceIdEnabled && (
            <div className="relative flex flex-col items-center scale-90">
                <svg className="absolute inset-[-10px] w-[calc(100%+20px)] h-[calc(100%+20px)] -rotate-90 pointer-events-none">
                    <circle cx="50%" cy="50%" r="24" className={`fill-none transition-all duration-150 ${success ? 'stroke-green-500' : isScanning ? 'stroke-blue-400' : 'stroke-white/5'}`} strokeWidth="4" strokeDasharray="150.8" strokeDashoffset={150.8 - (150.8 * scanProgress) / 100} strokeLinecap="round" />
                </svg>
                <button
                    onPointerDown={startFingerprintScan}
                    onPointerUp={stopFingerprintScan}
                    onPointerLeave={stopFingerprintScan}
                    className={`p-4 rounded-full border-2 transition-all relative z-10 ${success ? 'bg-green-600 text-white' : isScanning ? 'bg-blue-600 text-white scale-110 shadow-lg' : 'bg-white/5 text-white/20'}`}
                >
                    <FingerprintIcon className="w-8 h-8" />
                    {isScanning && <div className="absolute inset-0 animate-[laser_0.6s_infinite_linear] h-1 bg-blue-100/50 shadow-xl" />}
                </button>
            </div>
        )}
      </div>

      <style>{`
        @keyframes laser { 0% { transform: translateY(-10px); } 100% { transform: translateY(60px); } }
        @keyframes face { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(112px); } }
      `}</style>
    </div>
  );
};

export default LockScreen;

import type React from 'react';

export interface AppItem {
  id: string;
  name: string;
  icon: React.ComponentType<{ className?: string }>;
  color: string;
  action: () => void;
  isCustom?: boolean;
}

export interface StoredApp {
  id: string;
  name: string;
  url: string;
  iconIdentifier: string; // Can be a key from iconMap or a URL for a favicon
  color: string;
}

export interface LauncherSettings {
  passwordEnabled: boolean;
  passwordHash: string;
  fingerprintEnabled: boolean;
  faceIdEnabled: boolean;
  faceIdReference?: string; // Base64 of the enrolled face
}

import React, { useState, useMemo, useEffect } from 'react';
import Header from './components/Header';
import Clock from './components/Clock';
import SearchBar from './components/SearchBar';
import AppCard from './components/AppCard';
import AddAppModal from './components/AddAppModal';
import LockScreen from './components/LockScreen';
import SettingsModal from './components/SettingsModal';
import type { AppItem, StoredApp, LauncherSettings } from './types';
import { 
  MailIcon, CalendarIcon, PhotosIcon, MusicIcon, SettingsIcon, 
  BrowserIcon, FilesIcon, MapsIcon, GameIcon, PlayStoreIcon, 
  UserIcon, CodeIcon, LinkIcon, iconMap 
} from './components/Icons';

const LOCAL_STORAGE_KEY = 'plus-launcher-custom-apps';
const SETTINGS_KEY = 'plus-launcher-settings';

const UrlIcon: React.FC<{ src: string; name: string; className?: string }> = ({ src, name, className }) => {
  const [hasError, setHasError] = useState(false);

  useEffect(() => {
    setHasError(false);
  }, [src]);

  if (hasError || !src) {
    return <LinkIcon className={className} />;
  }

  return (
    <img 
      src={src} 
      alt={name} 
      className={`${className} object-cover rounded-md`} 
      onError={() => setHasError(true)}
    />
  );
};

export default function App() {
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditMode, setIsEditMode] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isLockSetupOpen, setIsLockSetupOpen] = useState(false);
  const [isFingerprintSetupOpen, setIsFingerprintSetupOpen] = useState(false);
  const [isFaceIdSetupOpen, setIsFaceIdSetupOpen] = useState(false);

  const [settings, setSettings] = useState<LauncherSettings>(() => {
    try {
      const stored = localStorage.getItem(SETTINGS_KEY);
      const defaults: LauncherSettings = { 
        passwordEnabled: false, 
        passwordHash: '', 
        fingerprintEnabled: false,
        faceIdEnabled: false,
        faceIdReference: undefined
      };
      return stored ? { ...defaults, ...JSON.parse(stored) } : defaults;
    } catch (e) {
      return { passwordEnabled: false, passwordHash: '', fingerprintEnabled: false, faceIdEnabled: false };
    }
  });

  const [isLocked, setIsLocked] = useState(() => {
    return !!(settings.passwordEnabled && settings.passwordHash);
  });

  const [customApps, setCustomApps] = useState<StoredApp[]>([]);
  const [editingApp, setEditingApp] = useState<StoredApp | null>(null);

  const loadApps = () => {
    try {
      const stored = localStorage.getItem(LOCAL_STORAGE_KEY);
      if (stored) {
        const parsed = JSON.parse(stored);
        if (Array.isArray(parsed)) setCustomApps(parsed);
      }
    } catch (error) {
      console.error("Failed to load apps", error);
    }
  };

  useEffect(() => {
    loadApps();
  }, []);

  const saveApps = (newApps: StoredApp[]) => {
    setCustomApps(newApps);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(newApps));
  };

  const saveSettings = (newSettings: LauncherSettings) => {
    setSettings(newSettings);
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(newSettings));
  };

  const handleSaveApp = (app: StoredApp) => {
    let newApps;
    if (editingApp) {
      newApps = customApps.map(a => a.id === app.id ? app : a);
    } else {
      newApps = [...customApps, app];
    }
    saveApps(newApps);
    setIsModalOpen(false);
    setEditingApp(null);
  };

  const handleDeleteApp = (id: string) => {
    if (confirm('Are you sure you want to delete this app?')) {
      const newApps = customApps.filter(app => app.id !== id);
      saveApps(newApps);
    }
  };

  const handleUnlockAttempt = (attempt: string): boolean => {
    if (attempt === 'biometric' || attempt === 'faceid') {
      setIsLocked(false);
      return true;
    }

    const hashedAttempt = btoa(attempt);
    if (hashedAttempt === settings.passwordHash) {
      setIsLocked(false);
      return true;
    }
    return false;
  };

  const handleSetPasscode = (passcode: string): boolean => {
    if (passcode.length < 4) return false;
    const hashed = btoa(passcode);
    saveSettings({
        ...settings,
        passwordEnabled: true,
        passwordHash: hashed
    });
    setIsLockSetupOpen(false);
    return true;
  };

  const handleCompleteBiometricEnrollment = (type: string, data?: string): boolean => {
    if (type === 'biometric') {
        saveSettings({ ...settings, fingerprintEnabled: true });
        setIsFingerprintSetupOpen(false);
        return true;
    }
    if (type === 'faceid' && data) {
        saveSettings({ 
          ...settings, 
          faceIdEnabled: true, 
          faceIdReference: data 
        });
        setIsFaceIdSetupOpen(false);
        return true;
    }
    return false;
  };

  const togglePasswordFeature = () => {
    if (settings.passwordEnabled) {
        if (confirm('Disable all security features (PIN, Biometrics)?')) {
            saveSettings({
                ...settings,
                passwordEnabled: false,
                passwordHash: '',
                fingerprintEnabled: false,
                faceIdEnabled: false,
                faceIdReference: undefined
            });
        }
    } else {
        setIsLockSetupOpen(true);
    }
  };

  const toggleFingerprintFeature = () => {
    if (settings.fingerprintEnabled) {
        saveSettings({ ...settings, fingerprintEnabled: false });
    } else {
        setIsFingerprintSetupOpen(true);
    }
  };

  const toggleFaceIdFeature = () => {
    if (settings.faceIdEnabled) {
        saveSettings({ ...settings, faceIdEnabled: false, faceIdReference: undefined });
    } else {
        setIsFaceIdSetupOpen(true);
    }
  };

  const defaultApps: AppItem[] = [
    {
      id: 'chrome',
      name: 'Chrome',
      icon: BrowserIcon,
      color: '#2563eb',
      action: () => window.open('https://www.google.com', '_blank'),
      isCustom: false
    },
    {
      id: 'roblox',
      name: 'Roblox',
      icon: GameIcon,
      color: '#ef4444',
      action: () => window.open('https://www.roblox.com', '_blank'),
      isCustom: false
    },
    {
      id: 'minecraft',
      name: 'Minecraft',
      icon: GameIcon,
      color: '#10b981',
      action: () => window.open('https://www.minecraft.net', '_blank'),
      isCustom: false
    },
    {
      id: 'playstore',
      name: 'Google Play',
      icon: PlayStoreIcon,
      color: '#0ea5e9',
      action: () => window.open('https://play.google.com', '_blank'),
      isCustom: false
    },
    {
      id: 'colab',
      name: 'Google Colab',
      icon: CodeIcon,
      color: '#f97316',
      action: () => window.open('https://colab.research.google.com/', '_blank'),
      isCustom: false
    },
    {
      id: 'photos',
      name: 'Photos',
      icon: PhotosIcon,
      color: '#ec4899',
      action: () => window.open('https://photos.google.com', '_blank'),
      isCustom: false
    },
    {
        id: 'launcher-settings',
        name: 'Launcher Settings',
        icon: SettingsIcon,
        color: '#475569',
        action: () => setIsSettingsOpen(true),
        isCustom: false
    }
  ];

  const mappedCustomApps: AppItem[] = customApps.map(app => {
    let IconComponent = LinkIcon;
    if (app.iconIdentifier && iconMap[app.iconIdentifier]) {
        IconComponent = iconMap[app.iconIdentifier];
    } else if (app.iconIdentifier && app.iconIdentifier.startsWith('http')) {
        IconComponent = ({ className }) => <UrlIcon src={app.iconIdentifier} name={app.name} className={className} />;
    }

    return {
        id: app.id,
        name: app.name,
        icon: IconComponent,
        color: app.color,
        action: () => window.open(app.url, '_blank'),
        isCustom: true
    };
  });

  const allApps = [...defaultApps, ...mappedCustomApps];
  const filteredApps = allApps.filter(app => app.name.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="min-h-screen bg-gray-900 p-6 md:p-12 font-sans selection:bg-blue-500/30 overflow-x-hidden relative">
        <div className="fixed top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/10 blur-[120px] rounded-full pointer-events-none animate-pulse-bg" />
        <div className="fixed bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full pointer-events-none animate-pulse-bg animation-delay-4000" />

        {isLocked && (
          <LockScreen 
            onUnlock={handleUnlockAttempt} 
            fingerprintEnabled={settings.fingerprintEnabled}
            faceIdEnabled={settings.faceIdEnabled}
            faceIdReference={settings.faceIdReference}
          />
        )}

        {isLockSetupOpen && <LockScreen onUnlock={handleSetPasscode} isSetup={true} />}
        {isFingerprintSetupOpen && <LockScreen onUnlock={(at) => handleCompleteBiometricEnrollment(at)} isFingerprintSetup={true} />}
        {isFaceIdSetupOpen && <LockScreen onUnlock={(at, data) => handleCompleteBiometricEnrollment(at, data)} isFaceIdSetup={true} />}

        <div className="max-w-7xl mx-auto space-y-12 relative z-10">
            <Header 
                isEditMode={isEditMode} 
                onToggleEditMode={() => setIsEditMode(!isEditMode)}
                hasCustomApps={customApps.length > 0}
                onReload={loadApps}
                onLock={settings.passwordEnabled ? () => setIsLocked(true) : undefined}
            />

            <div className="space-y-8">
                <Clock />
                <SearchBar value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4 sm:gap-6">
                {filteredApps.map(app => (
                    <AppCard 
                        key={app.id} 
                        app={app} 
                        isEditMode={isEditMode}
                        onEdit={() => {
                            const stored = customApps.find(a => a.id === app.id);
                            if (stored) { setEditingApp(stored); setIsModalOpen(true); }
                        }}
                        onDelete={() => handleDeleteApp(app.id)}
                    />
                ))}

                <button
                    onClick={() => { setEditingApp(null); setIsModalOpen(true); }}
                    className="aspect-square flex flex-col items-center justify-center p-4 rounded-2xl border-2 border-dashed border-gray-700 text-gray-500 hover:text-white hover:border-gray-500 hover:bg-gray-800/30 transition-all duration-300 group"
                >
                    <div className="p-4 rounded-full bg-gray-800 group-hover:bg-gray-700 transition-colors mb-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                        </svg>
                    </div>
                    <span className="text-sm font-medium">Add App</span>
                </button>
            </div>
        </div>

        <AddAppModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={handleSaveApp} appToEdit={editingApp} />

        <SettingsModal 
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            isEditMode={isEditMode}
            onToggleEditMode={() => setIsEditMode(!isEditMode)}
            passwordEnabled={settings.passwordEnabled}
            onManagePassword={togglePasswordFeature}
            onLock={() => { setIsSettingsOpen(false); setIsLocked(true); }}
            fingerprintEnabled={settings.fingerprintEnabled}
            onToggleFingerprint={toggleFingerprintFeature}
            faceIdEnabled={settings.faceIdEnabled}
            onToggleFaceId={toggleFaceIdFeature}
        />
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import Clock from './Clock';
import { LockIcon, ShieldCheckIcon, FingerprintIcon, FaceIdIcon } from './Icons';
import { GoogleGenAI } from "@google/genai";

interface LockScreenProps {
  onUnlock: (password: string, data?: string) => boolean;
  isSetup?: boolean;
  isFingerprintSetup?: boolean;
  isFaceIdSetup?: boolean;
  fingerprintEnabled?: boolean;
  faceIdEnabled?: boolean;
  faceIdReference?: string;
}

const LockScreen: React.FC<LockScreenProps> = ({ 
    onUnlock, isSetup, isFingerprintSetup, isFaceIdSetup, fingerprintEnabled, faceIdEnabled, faceIdReference
}) => {
  const [input, setInput] = useState('');
  const [error, setError] = useState(false);
  const [success, setSuccess] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const [scanProgress, setScanProgress] = useState(0);
  const [analysisText, setAnalysisText] = useState('SECURE');
  const [ready, setReady] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const scanTimerRef = useRef<number | null>(null);

  useEffect(() => {
    const t = setTimeout(() => setReady(true), 50);
    return () => clearTimeout(t);
  }, []);

  // Face ID Camera Stream
  useEffect(() => {
    if (isFaceIdSetup || faceIdEnabled) {
        navigator.mediaDevices.getUserMedia({ video: true })
            .then(stream => {
                if (videoRef.current) videoRef.current.srcObject = stream;
                if (faceIdEnabled && !isFaceIdSetup) {
                    setTimeout(startFaceScan, 800);
                }
            })
            .catch(err => {
                console.error("Camera denied", err);
                setAnalysisText("CAM ERROR");
            });

        return () => {
            if (videoRef.current?.srcObject) {
                (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
            }
        };
    }
  }, [isFaceIdSetup, faceIdEnabled]);

  const verifyFaceWithAI = async (currentBase64: string) => {
    setIsVerifying(true);
    setAnalysisText("AI VERIFYING...");

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        let prompt = "";
        let parts: any[] = [];

        if (isFaceIdSetup) {
          // During enrollment, just verify it's a valid face
          prompt = "Analyze this camera frame for enrollment. Return exactly 'VALID' if you see a clear, well-lit human face looking directly at the camera. Return 'INVALID' if the image is blurry, dark, blocked, or contains no clear face. Answer in one word only.";
          parts = [
            { text: prompt },
            { inlineData: { mimeType: 'image/jpeg', data: currentBase64 } }
          ];
        } else if (faceIdReference) {
          // During unlock, compare against the reference
          prompt = "Security Check: Compare these two photos. Photo 1 is the authorized owner. Photo 2 is the person currently trying to unlock the device. Return exactly 'VALID' ONLY if Photo 2 clearly shows the same individual as Photo 1. If it is a different person, a photo of a photo, a mask, or if Photo 2 is too blurry/dark to confirm, return 'INVALID'. Be extremely strict. Answer in one word only.";
          parts = [
            { text: prompt },
            { inlineData: { mimeType: 'image/jpeg', data: faceIdReference } }, // Photo 1
            { inlineData: { mimeType: 'image/jpeg', data: currentBase64 } }    // Photo 2
          ];
        } else {
          throw new Error("No reference face found.");
        }

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: [{ parts }]
        });

        const result = response.text?.trim().toUpperCase();
        if (result === 'VALID') {
            setSuccess(true);
            onUnlock('faceid', currentBase64); // Pass the frame data back during enrollment
        } else {
            throw new Error("Face verification failed");
        }
    } catch (err) {
        setError(true);
        setAnalysisText("IDENTITY MISMATCH");
        setIsVerifying(false);
        setIsScanning(false);
        setScanProgress(0);
        setTimeout(() => {
            setError(false);
            setAnalysisText(isFaceIdSetup ? "RE-ENROLL" : "RETRY");
        }, 2000);
    }
  };

  const captureAndVerify = () => {
    if (!videoRef.current || !canvasRef.current) return;

    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const dataUrl = canvas.toDataURL('image/jpeg', 0.6);
    const base64 = dataUrl.split(',')[1];

    verifyFaceWithAI(base64);
  };

  const startFaceScan = () => {
    if (isScanning || isVerifying || success) return;
    setIsScanning(true);
    setScanProgress(0);
    setError(false);
    setAnalysisText("SCANNING...");

    let progress = 0;
    const interval = setInterval(() => {
        progress += 3;
        setScanProgress(Math.min(progress, 100));
        if (progress >= 100) {
            clearInterval(interval);
            captureAndVerify();
        }
    }, 30);
  };

  const handleKeypad = (num: string) => {
    if (input.length < 8) {
      setInput(prev => prev + num);
      setError(false);
    }
  };

  const handleBackspace = () => {
    setInput(prev => prev.slice(0, -1));
    setError(false);
  };

  const handleUnlock = () => {
    const isValid = onUnlock(input);
    if (isValid) setSuccess(true);
    else {
      setError(true);
      setTimeout(() => setInput(''), 300);
    }
  };

  const stopFingerprintScan = (e?: React.PointerEvent) => {
    if (e) try { (e.currentTarget as HTMLElement).releasePointerCapture(e.pointerId); } catch(err) {}
    if (scanTimerRef.current) clearInterval(scanTimerRef.current);
    if (!success) {
      setIsScanning(false);
      setScanProgress(0);
      setAnalysisText('HOLD');
    }
  };

  const startFingerprintScan = (e: React.PointerEvent) => {
    if (!ready || isScanning || success) return;
    try { (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId); } catch(err) {}
    setIsScanning(true);
    setScanProgress(0);
    setError(false);

    const analysisSteps = ["Sampling...", "Mapping", "Verifying"];
    const duration = isFingerprintSetup ? 1200 : 800;
    const steps = duration / 16;
    let currentStep = 0;

    scanTimerRef.current = window.setInterval(() => {
        currentStep++;
        const progress = Math.min((currentStep / steps) * 100, 100);
        setScanProgress(progress);

        const textIdx = Math.floor((progress / 100) * analysisSteps.length);
        setAnalysisText(analysisSteps[textIdx] || "Verifying");

        if (currentStep >= steps) {
            clearInterval(scanTimerRef.current!);
            if (onUnlock('biometric')) setSuccess(true);
            else { setError(true); setIsScanning(false); setScanProgress(0); }
        }
    }, 16);
  };

  return (
    <div className="fixed inset-0 z-[110] bg-gray-950/98 backdrop-blur-3xl flex flex-col items-center justify-start py-4 px-2 select-none touch-none overflow-hidden">
      <div className={`absolute inset-0 transition-opacity duration-700 ${isScanning || isVerifying ? 'opacity-30' : 'opacity-0'} ${error ? 'bg-red-600/20' : 'bg-blue-600/20'} blur-[80px] pointer-events-none`} />

      <canvas ref={canvasRef} className="hidden" />

      <div className={`transition-all duration-700 origin-top mb-1 ${isFingerprintSetup || isFaceIdSetup ? 'scale-[0.3] opacity-0 h-0' : 'scale-[0.4] sm:scale-60'}`}>
        <Clock />
      </div>

      <div className={`w-full max-w-[240px] flex flex-col items-center space-y-2 transition-all duration-500 ${error ? 'animate-wiggle' : ''} ${success ? 'scale-125 opacity-0 pointer-events-none' : 'opacity-100'}`}>

        {/* Guard Header */}
        <div className="flex flex-col items-center gap-0.5">
          <div className={`p-1.5 rounded-lg transition-all duration-300 ${success ? 'bg-green-600 shadow-[0_0_20px_rgba(34,197,94,0.5)]' : error ? 'bg-red-600' : isVerifying ? 'bg-amber-600 animate-pulse' : isScanning ? 'bg-blue-600' : 'bg-white/5'} text-white`}>
            {isSetup ? <ShieldCheckIcon className="w-4 h-4" /> : (isFaceIdSetup || faceIdEnabled) ? <FaceIdIcon className="w-4 h-4" /> : <FingerprintIcon className="w-4 h-4" />}
          </div>
          <div className="text-center">
            <h2 className="text-[10px] font-black text-white tracking-[0.1em] uppercase">Plus Guard</h2>
            <p className={`h-3 text-[8px] font-bold tracking-widest uppercase transition-colors ${success ? 'text-green-400' : error ? 'text-red-400' : isVerifying ? 'text-amber-400' : isScanning ? 'text-blue-400' : 'text-gray-500'}`}>
               {success ? 'Authorized' : analysisText}
            </p>
          </div>
        </div>

        {/* Face ID Viewbox */}
        {(isFaceIdSetup || faceIdEnabled) && (
            <div className={`relative w-28 h-28 rounded-full border-2 transition-colors duration-500 overflow-hidden bg-black mb-1 ${success ? 'border-green-500' : error ? 'border-red-500' : isVerifying ? 'border-amber-500' : 'border-white/10'}`}>
                <video ref={videoRef} autoPlay playsInline muted className={`w-full h-full object-cover transition-all duration-500 ${success ? 'grayscale-0 brightness-100' : 'grayscale brightness-125'}`} />

                {(isScanning || isVerifying) && (
                    <div className="absolute inset-0 z-10 pointer-events-none">
                        <div className={`w-full h-0.5 shadow-lg absolute top-0 left-0 animate-[face_1.5s_infinite_ease-in-out] ${isVerifying ? 'bg-amber-400 shadow-[0_0_15px_amber]' : 'bg-blue-400 shadow-[0_0_15px_blue]'}`} />
                        <div className={`absolute inset-4 border-2 rounded-full animate-pulse ${isVerifying ? 'border-amber-400/30' : 'border-blue-400/30'}`} />
                    </div>
                )}

                {isFaceIdSetup && !isScanning && !isVerifying && (
                    <button onClick={startFaceScan} className="absolute inset-0 bg-blue-600/80 text-white text-[10px] font-bold uppercase flex flex-col items-center justify-center gap-1">
                        <FaceIdIcon className="w-6 h-6" />
                        Enroll Face
                    </button>
                )}

                {faceIdEnabled && error && !isScanning && !isVerifying && (
                    <button onClick={startFaceScan} className="absolute inset-0 bg-red-600/80 text-white text-[9px] font-bold uppercase flex items-center justify-center">Try Again</button>
                )}
            </div>
        )}

        {/* PIN Pad */}
        {!isFingerprintSetup && !isFaceIdSetup && !isScanning && !isVerifying && (
            <div className="flex flex-col items-center gap-2 w-full">
                <div className="flex justify-center gap-1.5 h-3">
                    {Array.from({ length: Math.max(input.length, 4) }).map((_, i) => (
                        <div key={i} className={`w-1.5 h-1.5 rounded-full border transition-all ${i < input.length ? 'bg-blue-500 border-blue-500 scale-110 shadow-[0_0_10px_rgba(59,130,246,0.5)]' : 'border-white/10 bg-transparent'}`} />
                    ))}
                </div>
                <div className="grid grid-cols-3 gap-1.5 w-full max-w-[150px]">
                    {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                        <button key={num} onClick={() => handleKeypad(num.toString())} className="aspect-square rounded-lg bg-white/5 text-white text-sm font-bold border border-white/5 active:bg-blue-600/30 transition-colors">{num}</button>
                    ))}
                    <button onClick={handleBackspace} className="aspect-square flex items-center justify-center text-white/20 active:text-white"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeWidth={2.5} d="M12 9.75L14.25 12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12L12 14.25m-2.58 4.92l-6.37-6.37a2.25 2.25 0 010-3.18l6.37-6.37A2.25 2.25 0 0110.47 2.25h10.28c1.242 0 2.25 1.008 2.25 2.25v15a2.25 2.25 0 01-2.25 2.25H10.47a2.25 2.25 0 01-1.47-.58z" /></svg></button>
                    <button onClick={() => handleKeypad('0')} className="aspect-square rounded-lg bg-white/5 text-white text-sm font-bold border border-white/5 active:bg-blue-600/30">0</button>
                    <button onClick={handleUnlock} disabled={input.length < 4} className="aspect-square flex items-center justify-center rounded-lg bg-blue-600 text-white active:scale-95 disabled:opacity-5 shadow-lg"><svg className="w-4 h-4" fill="none" stroke="currentColor" strokeWidth={3} viewBox="0 0 24 24"><path d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" /></svg></button>
                </div>
            </div>
        )}

        {/* Fingerprint Button */}
        {(isFingerprintSetup || fingerprintEnabled) && !isFaceIdSetup && !faceIdEnabled && (
            <div className="relative flex flex-col items-center scale-90">
                <svg className="absolute inset-[-10px] w-[calc(100%+20px)] h-[calc(100%+20px)] -rotate-90 pointer-events-none">
                    <circle cx="50%" cy="50%" r="24" className={`fill-none transition-all duration-150 ${success ? 'stroke-green-500' : isScanning ? 'stroke-blue-400' : 'stroke-white/5'}`} strokeWidth="4" strokeDasharray="150.8" strokeDashoffset={150.8 - (150.8 * scanProgress) / 100} strokeLinecap="round" />
                </svg>
                <button
                    onPointerDown={startFingerprintScan}
                    onPointerUp={stopFingerprintScan}
                    onPointerLeave={stopFingerprintScan}
                    className={`p-4 rounded-full border-2 transition-all relative z-10 ${success ? 'bg-green-600 text-white' : isScanning ? 'bg-blue-600 text-white scale-110 shadow-lg' : 'bg-white/5 text-white/20'}`}
                >
                    <FingerprintIcon className="w-8 h-8" />
                    {isScanning && <div className="absolute inset-0 animate-[laser_0.6s_infinite_linear] h-1 bg-blue-100/50 shadow-xl" />}
                </button>
            </div>
        )}
      </div>

      <style>{`
        @keyframes laser { 0% { transform: translateY(-10px); } 100% { transform: translateY(60px); } }
        @keyframes face { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(112px); } }
      `}</style>
    </div>
  );
};

export default LockScreen;

import type React from 'react';

export interface AppItem {
  id: string;
  name: string;
  icon: React.ComponentType<{ className?: string }>;
  color: string;
  action: () => void;
  isCustom?: boolean;
}

export interface StoredApp {
  id: string;
  name: string;
  url: string;
  iconIdentifier: string; // Can be a key from iconMap or a URL for a favicon
  color: string;
}

export interface LauncherSettings {
  passwordEnabled: boolean;
  passwordHash: string;
  fingerprintEnabled: boolean;
  faceIdEnabled: boolean;
  faceIdReference?: string; // Base64 of the enrolled face
  recoveryQuestion?: string;
  recoveryAnswerHash?: string;
}

import React, { useState, useMemo, useEffect } from 'react';
import Header from './components/Header';
import Clock from './components/Clock';
import SearchBar from './components/SearchBar';
import AppCard from './components/AppCard';
import AddAppModal from './components/AddAppModal';
import LockScreen from './components/LockScreen';
import SettingsModal from './components/SettingsModal';
import type { AppItem, StoredApp, LauncherSettings } from './types';
import { 
  MailIcon, CalendarIcon, PhotosIcon, MusicIcon, SettingsIcon, 
  BrowserIcon, FilesIcon, MapsIcon, GameIcon, PlayStoreIcon, 
  UserIcon, CodeIcon, LinkIcon, iconMap 
} from './components/Icons';

const LOCAL_STORAGE_KEY = 'plus-launcher-custom-apps';
const SETTINGS_KEY = 'plus-launcher-settings';

const UrlIcon: React.FC<{ src: string; name: string; className?: string }> = ({ src, name, className }) => {
  const [hasError, setHasError] = useState(false);

  useEffect(() => {
    setHasError(false);
  }, [src]);

  if (hasError || !src) {
    return <LinkIcon className={className} />;
  }

  return (
    <img 
      src={src} 
      alt={name} 
      className={`${className} object-cover rounded-md`} 
      onError={() => setHasError(true)}
    />
  );
};

export default function App() {
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditMode, setIsEditMode] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isLockSetupOpen, setIsLockSetupOpen] = useState(false);
  const [isFingerprintSetupOpen, setIsFingerprintSetupOpen] = useState(false);
  const [isFaceIdSetupOpen, setIsFaceIdSetupOpen] = useState(false);

  const [settings, setSettings] = useState<LauncherSettings>(() => {
    try {
      const stored = localStorage.getItem(SETTINGS_KEY);
      const defaults: LauncherSettings = { 
        passwordEnabled: false, 
        passwordHash: '', 
        fingerprintEnabled: false,
        faceIdEnabled: false,
        faceIdReference: undefined,
        recoveryQuestion: undefined,
        recoveryAnswerHash: undefined
      };
      return stored ? { ...defaults, ...JSON.parse(stored) } : defaults;
    } catch (e) {
      return { passwordEnabled: false, passwordHash: '', fingerprintEnabled: false, faceIdEnabled: false };
    }
  });

  const [isLocked, setIsLocked] = useState(() => {
    return !!(settings.passwordEnabled && settings.passwordHash);
  });

  const [customApps, setCustomApps] = useState<StoredApp[]>([]);
  const [editingApp, setEditingApp] = useState<StoredApp | null>(null);

  const loadApps = () => {
    try {
      const stored = localStorage.getItem(LOCAL_STORAGE_KEY);
      if (stored) {
        const parsed = JSON.parse(stored);
        if (Array.isArray(parsed)) setCustomApps(parsed);
      }
    } catch (error) {
      console.error("Failed to load apps", error);
    }
  };

  useEffect(() => {
    loadApps();
  }, []);

  const saveApps = (newApps: StoredApp[]) => {
    setCustomApps(newApps);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(newApps));
  };

  const saveSettings = (newSettings: LauncherSettings) => {
    setSettings(newSettings);
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(newSettings));
  };

  const handleSaveApp = (app: StoredApp) => {
    let newApps;
    if (editingApp) {
      newApps = customApps.map(a => a.id === app.id ? app : a);
    } else {
      newApps = [...customApps, app];
    }
    saveApps(newApps);
    setIsModalOpen(false);
    setEditingApp(null);
  };

  const handleDeleteApp = (id: string) => {
    if (confirm('Are you sure you want to delete this app?')) {
      const newApps = customApps.filter(app => app.id !== id);
      saveApps(newApps);
    }
  };

  const handleUnlockAttempt = (attempt: string): boolean => {
    if (attempt === 'biometric' || attempt === 'faceid' || attempt === 'recovery_success') {
      setIsLocked(false);
      return true;
    }

    const hashedAttempt = btoa(attempt);
    if (hashedAttempt === settings.passwordHash) {
      setIsLocked(false);
      return true;
    }
    return false;
  };

  const handleSetPasscode = (passcode: string, recoveryData?: { question: string, answer: string }): boolean => {
    if (passcode.length < 4) return false;
    const hashed = btoa(passcode);

    const newSettings = {
        ...settings,
        passwordEnabled: true,
        passwordHash: hashed
    };

    if (recoveryData) {
      newSettings.recoveryQuestion = recoveryData.question;
      newSettings.recoveryAnswerHash = btoa(recoveryData.answer.toLowerCase().trim());
    }

    saveSettings(newSettings);
    setIsLockSetupOpen(false);
    return true;
  };

  const handleCompleteBiometricEnrollment = (type: string, data?: string): boolean => {
    if (type === 'biometric') {
        saveSettings({ ...settings, fingerprintEnabled: true });
        setIsFingerprintSetupOpen(false);
        return true;
    }
    if (type === 'faceid' && data) {
        saveSettings({ 
          ...settings, 
          faceIdEnabled: true, 
          faceIdReference: data 
        });
        setIsFaceIdSetupOpen(false);
        return true;
    }
    return false;
  };

  const togglePasswordFeature = () => {
    if (settings.passwordEnabled) {
        if (confirm('Disable all security features (PIN, Biometrics)?')) {
            saveSettings({
                ...settings,
                passwordEnabled: false,
                passwordHash: '',
                fingerprintEnabled: false,
                faceIdEnabled: false,
                faceIdReference: undefined,
                recoveryQuestion: undefined,
                recoveryAnswerHash: undefined
            });
        }
    } else {
        setIsLockSetupOpen(true);
    }
  };

  const toggleFingerprintFeature = () => {
    if (settings.fingerprintEnabled) {
        saveSettings({ ...settings, fingerprintEnabled: false });
    } else {
        setIsFingerprintSetupOpen(true);
    }
  };

  const toggleFaceIdFeature = () => {
    if (settings.faceIdEnabled) {
        saveSettings({ ...settings, faceIdEnabled: false, faceIdReference: undefined });
    } else {
        setIsFaceIdSetupOpen(true);
    }
  };

  const defaultApps: AppItem[] = [
    {
      id: 'chrome',
      name: 'Chrome',
      icon: BrowserIcon,
      color: '#2563eb',
      action: () => window.open('https://www.google.com', '_blank'),
      isCustom: false
    },
    {
      id: 'roblox',
      name: 'Roblox',
      icon: GameIcon,
      color: '#ef4444',
      action: () => window.open('https://www.roblox.com', '_blank'),
      isCustom: false
    },
    {
      id: 'minecraft',
      name: 'Minecraft',
      icon: GameIcon,
      color: '#10b981',
      action: () => window.open('https://www.minecraft.net', '_blank'),
      isCustom: false
    },
    {
      id: 'playstore',
      name: 'Google Play',
      icon: PlayStoreIcon,
      color: '#0ea5e9',
      action: () => window.open('https://play.google.com', '_blank'),
      isCustom: false
    },
    {
      id: 'colab',
      name: 'Google Colab',
      icon: CodeIcon,
      color: '#f97316',
      action: () => window.open('https://colab.research.google.com/', '_blank'),
      isCustom: false
    },
    {
      id: 'photos',
      name: 'Photos',
      icon: PhotosIcon,
      color: '#ec4899',
      action: () => window.open('https://photos.google.com', '_blank'),
      isCustom: false
    },
    {
        id: 'launcher-settings',
        name: 'Launcher Settings',
        icon: SettingsIcon,
        color: '#475569',
        action: () => setIsSettingsOpen(true),
        isCustom: false
    }
  ];

  const mappedCustomApps: AppItem[] = customApps.map(app => {
    let IconComponent = LinkIcon;
    if (app.iconIdentifier && iconMap[app.iconIdentifier]) {
        IconComponent = iconMap[app.iconIdentifier];
    } else if (app.iconIdentifier && app.iconIdentifier.startsWith('http')) {
        IconComponent = ({ className }) => <UrlIcon src={app.iconIdentifier} name={app.name} className={className} />;
    }

    return {
        id: app.id,
        name: app.name,
        icon: IconComponent,
        color: app.color,
        action: () => window.open(app.url, '_blank'),
        isCustom: true
    };
  });

  const allApps = [...defaultApps, ...mappedCustomApps];
  const filteredApps = allApps.filter(app => app.name.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="min-h-screen bg-gray-900 p-6 md:p-12 font-sans selection:bg-blue-500/30 overflow-x-hidden relative">
        <div className="fixed top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/10 blur-[120px] rounded-full pointer-events-none animate-pulse-bg" />
        <div className="fixed bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full pointer-events-none animate-pulse-bg animation-delay-4000" />

        {isLocked && (
          <LockScreen 
            onUnlock={handleUnlockAttempt} 
            fingerprintEnabled={settings.fingerprintEnabled}
            faceIdEnabled={settings.faceIdEnabled}
            faceIdReference={settings.faceIdReference}
            recoveryQuestion={settings.recoveryQuestion}
            recoveryAnswerHash={settings.recoveryAnswerHash}
          />
        )}

        {isLockSetupOpen && <LockScreen onUnlock={handleSetPasscode} isSetup={true} />}
        {isFingerprintSetupOpen && <LockScreen onUnlock={(at) => handleCompleteBiometricEnrollment(at)} isFingerprintSetup={true} />}
        {isFaceIdSetupOpen && <LockScreen onUnlock={(at, data) => handleCompleteBiometricEnrollment(at, data)} isFaceIdSetup={true} />}

        <div className="max-w-7xl mx-auto space-y-12 relative z-10">
            <Header 
                isEditMode={isEditMode} 
                onToggleEditMode={() => setIsEditMode(!isEditMode)}
                hasCustomApps={customApps.length > 0}
                onReload={loadApps}
                onLock={settings.passwordEnabled ? () => setIsLocked(true) : undefined}
            />

            <div className="space-y-8">
                <Clock />
                <SearchBar value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4 sm:gap-6">
                {filteredApps.map(app => (
                    <AppCard 
                        key={app.id} 
                        app={app} 
                        isEditMode={isEditMode}
                        onEdit={() => {
                            const stored = customApps.find(a => a.id === app.id);
                            if (stored) { setEditingApp(stored); setIsModalOpen(true); }
                        }}
                        onDelete={() => handleDeleteApp(app.id)}
                    />
                ))}

                <button
                    onClick={() => { setEditingApp(null); setIsModalOpen(true); }}
                    className="aspect-square flex flex-col items-center justify-center p-4 rounded-2xl border-2 border-dashed border-gray-700 text-gray-500 hover:text-white hover:border-gray-500 hover:bg-gray-800/30 transition-all duration-300 group"
                >
                    <div className="p-4 rounded-full bg-gray-800 group-hover:bg-gray-700 transition-colors mb-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                        </svg>
                    </div>
                    <span className="text-sm font-medium">Add App</span>
                </button>
            </div>
        </div>

        <AddAppModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={handleSaveApp} appToEdit={editingApp} />

        <SettingsModal 
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            isEditMode={isEditMode}
            onToggleEditMode={() => setIsEditMode(!isEditMode)}
            passwordEnabled={settings.passwordEnabled}
            onManagePassword={togglePasswordFeature}
            onLock={() => { setIsSettingsOpen(false); setIsLocked(true); }}
            fingerprintEnabled={settings.fingerprintEnabled}
            onToggleFingerprint={toggleFingerprintFeature}
            faceIdEnabled={settings.faceIdEnabled}
            onToggleFaceId={toggleFaceIdFeature}
        />
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import Clock from './Clock';
import { LockIcon, ShieldCheckIcon, FingerprintIcon, FaceIdIcon } from './Icons';
import { GoogleGenAI } from "@google/genai";

interface LockScreenProps {
  onUnlock: (password: string, data?: any) => boolean;
  isSetup?: boolean;
  isFingerprintSetup?: boolean;
  isFaceIdSetup?: boolean;
  fingerprintEnabled?: boolean;
  faceIdEnabled?: boolean;
  faceIdReference?: string;
  recoveryQuestion?: string;
  recoveryAnswerHash?: string;
}

const LockScreen: React.FC<LockScreenProps> = ({ 
    onUnlock, isSetup, isFingerprintSetup, isFaceIdSetup, fingerprintEnabled, faceIdEnabled, faceIdReference, recoveryQuestion, recoveryAnswerHash
}) => {
  const [view, setView] = useState<'unlock' | 'recovery' | 'setup-recovery'>('unlock');
  const [input, setInput] = useState('');
  const [recoveryInput, setRecoveryInput] = useState('');
  const [setupQuestion, setSetupQuestion] = useState('');
  const [setupAnswer, setSetupAnswer] = useState('');
  const [error, setError] = useState(false);
  const [success, setSuccess] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const [scanProgress, setScanProgress] = useState(0);
  const [analysisText, setAnalysisText] = useState('SECURE');
  const [ready, setReady] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const scanTimerRef = useRef<number | null>(null);

  useEffect(() => {
    const t = setTimeout(() => setReady(true), 50);
    return () => clearTimeout(t);
  }, []);

  // Face ID Camera Stream
  useEffect(() => {
    if ((isFaceIdSetup || faceIdEnabled) && view === 'unlock') {
        navigator.mediaDevices.getUserMedia({ video: true })
            .then(stream => {
                if (videoRef.current) videoRef.current.srcObject = stream;
                if (faceIdEnabled && !isFaceIdSetup) {
                    setTimeout(startFaceScan, 800);
                }
            })
            .catch(err => {
                console.error("Camera denied", err);
                setAnalysisText("CAM ERROR");
            });

        return () => {
            if (videoRef.current?.srcObject) {
                (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
            }
        };
    }
  }, [isFaceIdSetup, faceIdEnabled, view]);

  const verifyFaceWithAI = async (currentBase64: string) => {
    setIsVerifying(true);
    setAnalysisText("AI VERIFYING...");

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        let prompt = "";
        let parts: any[] = [];

        if (isFaceIdSetup) {
          prompt = "Analyze this camera frame for enrollment. Return exactly 'VALID' if you see a clear, well-lit human face looking directly at the camera. Return 'INVALID' if the image is blurry, dark, blocked, or contains no clear face. Answer in one word only.";
          parts = [
            { text: prompt },
            { inlineData: { mimeType: 'image/jpeg', data: currentBase64 } }
          ];
        } else if (faceIdReference) {
          prompt = "Security Check: Compare these two photos. Photo 1 is the authorized owner. Photo 2 is the person currently trying to unlock the device. Return exactly 'VALID' ONLY if Photo 2 clearly shows the same individual as Photo 1. If it is a different person, a photo of a photo, a mask, or if Photo 2 is too blurry/dark to confirm, return 'INVALID'. Be extremely strict. Answer in one word only.";
          parts = [
            { text: prompt },
            { inlineData: { mimeType: 'image/jpeg', data: faceIdReference } }, // Photo 1
            { inlineData: { mimeType: 'image/jpeg', data: currentBase64 } }    // Photo 2
          ];
        } else {
          throw new Error("No reference face found.");
        }

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: [{ parts }]
        });

        const result = response.text?.trim().toUpperCase();
        if (result === 'VALID') {
            setSuccess(true);
            onUnlock('faceid', currentBase64);
        } else {
            throw new Error("Face verification failed");
        }
    } catch (err) {
        setError(true);
        setAnalysisText("IDENTITY MISMATCH");
        setIsVerifying(false);
        setIsScanning(false);
        setScanProgress(0);
        setTimeout(() => {
            setError(false);
            setAnalysisText(isFaceIdSetup ? "RE-ENROLL" : "RETRY");
