        name: 'Launcher Settings',
        icon: SettingsIcon,
        color: '#475569',
        action: () => setIsSettingsOpen(true),
        isCustom: false
    }
  ];

  const mappedCustomApps: AppItem[] = customApps.map(app => {
    let IconComponent = LinkIcon;
    if (app.iconIdentifier && iconMap[app.iconIdentifier]) {
        IconComponent = iconMap[app.iconIdentifier];
    } else if (app.iconIdentifier && app.iconIdentifier.startsWith('http')) {
        IconComponent = ({ className }) => <UrlIcon src={app.iconIdentifier} name={app.name} className={className} />;
    }

    return {
        id: app.id,
        name: app.name,
        icon: IconComponent,
        color: app.color,
        action: () => window.open(app.url, '_blank'),
        isCustom: true
    };
  });

  const allApps = [...defaultApps, ...mappedCustomApps];
  const filteredApps = allApps.filter(app => app.name.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="min-h-screen bg-gray-900 p-6 md:p-12 font-sans selection:bg-accent selection:text-white overflow-x-hidden relative">
        {/* Animated Glow Backgrounds mapped to Accent */}
        <div className="fixed top-[-10%] left-[-10%] w-[40%] h-[40%] bg-accent opacity-10 blur-[120px] rounded-full pointer-events-none animate-pulse-bg" />
        <div className="fixed bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full pointer-events-none animate-pulse-bg animation-delay-4000" />

        {isLocked && (
          <LockScreen 
            onUnlock={handleUnlockAttempt} 
            fingerprintEnabled={settings.fingerprintEnabled}
            faceIdEnabled={settings.faceIdEnabled}
            faceIdReference={settings.faceIdReference}
            recoveryQuestion={settings.recoveryQuestion}
            recoveryAnswerHash={settings.recoveryAnswerHash}
          />
        )}

        {isLockSetupOpen && <LockScreen onUnlock={handleSetPasscode} isSetup={true} />}
        {isFingerprintSetupOpen && <LockScreen onUnlock={(at) => handleCompleteBiometricEnrollment(at)} isFingerprintSetup={true} />}
        {isFaceIdSetupOpen && <LockScreen onUnlock={(at, data) => handleCompleteBiometricEnrollment(at, data)} isFaceIdSetup={true} />}
        {isRecoveryUpdateOpen && <LockScreen onUnlock={handleUpdateRecovery} isRecoveryUpdate={true} onCancel={() => setIsRecoveryUpdateOpen(false)} />}

        <div className="max-w-7xl mx-auto space-y-12 relative z-10">
            <Header 
                isEditMode={isEditMode} 
                onToggleEditMode={() => setIsEditMode(!isEditMode)}
                hasCustomApps={customApps.length > 0}
                onReload={loadApps}
                onLock={settings.passwordEnabled ? () => setIsLocked(true) : undefined}
            />

            <div className="space-y-8">
                <Clock />
                <SearchBar value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4 sm:gap-6">
                {filteredApps.map(app => (
                    <AppCard 
                        key={app.id} 
                        app={app} 
                        isEditMode={isEditMode}
                        onEdit={() => {
                            const stored = customApps.find(a => a.id === app.id);
                            if (stored) { setEditingApp(stored); setIsModalOpen(true); }
                        }}
                        onDelete={() => handleDeleteApp(app.id)}
                    />
                ))}

                <button
                    onClick={() => { setEditingApp(null); setIsModalOpen(true); }}
                    className="aspect-square flex flex-col items-center justify-center p-4 rounded-2xl border-2 border-dashed border-gray-700 text-gray-500 hover:text-white hover:border-gray-500 hover:bg-gray-800/30 transition-all duration-300 group focus:ring-2 focus:ring-accent focus:ring-offset-2 focus:ring-offset-gray-900 focus:outline-none"
                >
                    <div className="p-4 rounded-full bg-gray-800 group-hover:bg-gray-700 transition-colors mb-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                        </svg>
                    </div>
                    <span className="text-sm font-medium">Add App</span>
                </button>
            </div>
        </div>

        <AddAppModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={handleSaveApp} appToEdit={editingApp} />

        <SettingsModal 
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            isEditMode={isEditMode}
            onToggleEditMode={() => setIsEditMode(!isEditMode)}
            passwordEnabled={settings.passwordEnabled}
            onManagePassword={togglePasswordFeature}
            onLock={() => { setIsSettingsOpen(false); setIsLocked(true); }}
            fingerprintEnabled={settings.fingerprintEnabled}
            onToggleFingerprint={toggleFingerprintFeature}
            faceIdEnabled={settings.faceIdEnabled}
            onToggleFaceId={toggleFaceIdFeature}
            onManageRecovery={() => { setIsSettingsOpen(false); setIsRecoveryUpdateOpen(true); }}
            accentColor={settings.accentColor || '#3b82f6'}
            onSetAccentColor={handleSetAccentColor}
            accentColors={ACCENT_COLORS}
        />
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { iconMap, LinkIcon } from './Icons';
import type { StoredApp } from '../types';

interface AddAppModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (app: StoredApp) => void;
  appToEdit: StoredApp | null;
}

const colors = ['#3b82f6', '#ef4444', '#8b5cf6', '#ec4899', '#f97316', '#10b981', '#22c55e', '#64748b', '#f59e0b', '#06b6d4', '#d946ef', '#14b8a6'];
const iconNames = Object.keys(iconMap).filter(name => !['PencilIcon', 'TrashIcon'].includes(name));

const AddAppModal: React.FC<AddAppModalProps> = ({ isOpen, onClose, onSave, appToEdit }) => {
  const [name, setName] = useState('');
  const [url, setUrl] = useState('');
  const [selectedIcon, setSelectedIcon] = useState(iconNames[0]);
  const [selectedColor, setSelectedColor] = useState(colors[0]);
  const [useFavicon, setUseFavicon] = useState(true);
  const [faviconUrl, setFaviconUrl] = useState<string | null>(null);

  const isEditing = !!appToEdit;

  // Debounce favicon fetching
  useEffect(() => {
    if (!useFavicon || !url.trim()) {
      setFaviconUrl(null);
      return;
    }

    const handler = setTimeout(() => {
      try {
        const fullUrl = url.startsWith('http') ? url : `https://${url}`;
        const hostname = new URL(fullUrl).hostname;
        if (hostname) {
          setFaviconUrl(`https://www.google.com/s2/favicons?domain=${hostname}&sz=128`);
        } else {
          setFaviconUrl(null);
        }
      } catch (e) {
        setFaviconUrl(null);
      }
    }, 300);

    return () => {
      clearTimeout(handler);
    };
  }, [url, useFavicon]);

  useEffect(() => {
    if (isOpen) {
      if (appToEdit) {
        setName(appToEdit.name);
        setUrl(appToEdit.url);
        setSelectedColor(appToEdit.color);
        const isUrlIcon = appToEdit.iconIdentifier?.startsWith('http');
        setUseFavicon(isUrlIcon);
        if (isUrlIcon) {
          setSelectedIcon(iconNames[0]);
        } else {
          setSelectedIcon(appToEdit.iconIdentifier);
        }
      } else {
        setName('');
        setUrl('');
        setSelectedIcon(iconNames[0]);
        setSelectedColor(colors[0]);
        setUseFavicon(true);
      }
    }
  }, [isOpen, appToEdit]);

  useEffect(() => {
    const handleEsc = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        onClose();
      }
    };
    window.addEventListener('keydown', handleEsc);
    return () => {
      window.removeEventListener('keydown', handleEsc);
    };
  }, [onClose]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim() || !url.trim()) return;

    const formattedUrl = url.startsWith('http://') || url.startsWith('https://') ? url : `https://${url}`;

    const finalIconIdentifier = useFavicon && faviconUrl ? faviconUrl : selectedIcon;

    onSave({
      id: appToEdit?.id || Date.now().toString(),
      name,
      url: formattedUrl,
      iconIdentifier: finalIconIdentifier,
      color: selectedColor,
    });
  };

  if (!isOpen) return null;

  return (
    <div 
      className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex justify-center items-center p-4"
      onClick={onClose}
      role="dialog"
      aria-modal="true"
      aria-labelledby="add-app-title"
    >
      <div 
        className="bg-gray-800 border border-gray-700 rounded-2xl p-6 sm:p-8 w-full max-w-md shadow-2xl relative"
        onClick={(e) => e.stopPropagation()}
      >
        <button onClick={onClose} className="absolute top-4 right-4 text-gray-400 hover:text-white transition-colors" aria-label="Close dialog">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
        <h2 id="add-app-title" className="text-xl sm:text-2xl font-bold text-white mb-6">
          {isEditing ? 'Edit App' : 'Add Custom App'}
        </h2>
        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label htmlFor="appName" className="block text-sm font-medium text-gray-300 mb-2">App Name</label>
            <input
              id="appName"
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="e.g., My Portfolio"
              required
              className="w-full bg-gray-900/50 text-white placeholder-gray-500 border border-gray-600 rounded-lg py-2 px-4 focus:outline-none focus:ring-2 focus:ring-accent"
            />
          </div>
          <div>
            <label htmlFor="appUrl" className="block text-sm font-medium text-gray-300 mb-2">App URL</label>
            <input
              id="appUrl"
              type="text"
              value={url}
              onChange={(e) => setUrl(e.target.value)}
              placeholder="e.g., your-website.com"
              required
              className="w-full bg-gray-900/50 text-white placeholder-gray-500 border border-gray-600 rounded-lg py-2 px-4 focus:outline-none focus:ring-2 focus:ring-accent"
            />
          </div>

          <div>
            <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-gray-300">Icon</span>
                 <button type="button" onClick={() => setUseFavicon(!useFavicon)} className="text-sm text-accent hover:brightness-110 font-medium">
                    {useFavicon ? 'Choose an icon instead' : 'Use website icon'}
                 </button>
            </div>

            {useFavicon ? (
                <div className="bg-gray-900/50 p-3 rounded-lg flex items-center gap-4">
                    <div className="w-12 h-12 flex-shrink-0 bg-gray-700 rounded-lg flex items-center justify-center">
                        {faviconUrl ? (
                            <img src={faviconUrl} alt="Favicon preview" className="w-8 h-8 rounded-md" />
                        ) : (
                            <LinkIcon className="w-8 h-8 text-gray-400" />
                        )}
                    </div>
                    <div>
                        <p className="text-white font-medium">Website Icon (Favicon)</p>
                        <p className="text-xs text-gray-400">Automatically uses the site's icon.</p>
                    </div>
                </div>
            ) : (
                <div className="grid grid-cols-6 gap-2 bg-gray-900/50 p-2 rounded-lg overflow-y-auto max-h-32 custom-scrollbar">
                {iconNames.map(iconName => {
                    const Icon = iconMap[iconName];
                    return (
                    <button type="button" key={iconName} onClick={() => setSelectedIcon(iconName)} className={`aspect-square flex items-center justify-center rounded-md transition-all ${selectedIcon === iconName ? 'ring-2 ring-accent bg-accent/20' : 'hover:bg-gray-700'}`}>
                        <Icon className="h-6 w-6" style={{ color: selectedColor }} />
                    </button>
                    );
                })}
                </div>
            )}
          </div>

          <div>
            <span className="block text-sm font-medium text-gray-300 mb-2">App Identity Color</span>
            <div className="grid grid-cols-6 gap-2">
              {colors.map(color => (
                <button type="button" key={color} onClick={() => setSelectedColor(color)} className={`aspect-square rounded-full transition-all ${selectedColor === color ? 'ring-2 ring-offset-2 ring-offset-gray-800 ring-white' : 'hover:scale-110'}`} style={{ backgroundColor: color }} aria-label={`Select color ${color}`}></button>
              ))}
            </div>
          </div>
          <div className="pt-2">
            <button type="submit" disabled={!name.trim() || !url.trim()} className="w-full bg-accent hover:brightness-110 text-white font-bold py-3 px-4 rounded-lg transition-all focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-800 focus:ring-accent disabled:bg-gray-600 disabled:cursor-not-allowed shadow-lg shadow-accent/20">
              {isEditing ? 'Save Changes' : 'Add App'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddAppModal;

import React, { useState, useEffect, useRef } from 'react';
import Clock from './Clock';
// Add MailIcon to the imports
import { LockIcon, ShieldCheckIcon, FingerprintIcon, FaceIdIcon, MailIcon } from './Icons';
import { GoogleGenAI } from "@google/genai";

interface LockScreenProps {
  onUnlock: (password: string, data?: any) => boolean;
  isSetup?: boolean;
  isFingerprintSetup?: boolean;
  isFaceIdSetup?: boolean;
  isRecoveryUpdate?: boolean;
  onCancel?: () => void;
  fingerprintEnabled?: boolean;
  faceIdEnabled?: boolean;
  faceIdReference?: string;
  recoveryQuestion?: string;
  recoveryAnswerHash?: string;
}

const LockScreen: React.FC<LockScreenProps> = ({ 
    onUnlock, isSetup, isFingerprintSetup, isFaceIdSetup, isRecoveryUpdate, onCancel, fingerprintEnabled, faceIdEnabled, faceIdReference, recoveryQuestion, recoveryAnswerHash
}) => {
  const [view, setView] = useState<'unlock' | 'recovery' | 'setup-recovery'>(
    isRecoveryUpdate ? 'setup-recovery' : 'unlock'
  );
  const [input, setInput] = useState('');
  const [recoveryInput, setRecoveryInput] = useState('');
  const [setupQuestion, setSetupQuestion] = useState(isRecoveryUpdate && recoveryQuestion ? recoveryQuestion : '');
  const [setupAnswer, setSetupAnswer] = useState('');
  const [error, setError] = useState(false);
  const [success, setSuccess] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const [scanProgress, setScanProgress] = useState(0);
  const [analysisText, setAnalysisText] = useState('SECURE');
  const [ready, setReady] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const scanTimerRef = useRef<number | null>(null);

  useEffect(() => {
    const t = setTimeout(() => setReady(true), 50);
    return () => clearTimeout(t);
  }, []);

  // Face ID Camera Stream
  useEffect(() => {
    if ((isFaceIdSetup || faceIdEnabled) && view === 'unlock') {
        navigator.mediaDevices.getUserMedia({ video: true })
            .then(stream => {
                if (videoRef.current) videoRef.current.srcObject = stream;
                if (faceIdEnabled && !isFaceIdSetup) {
                    setTimeout(startFaceScan, 800);
                }
            })
            .catch(err => {
                console.error("Camera denied", err);
                setAnalysisText("CAM ERROR");
            });

        return () => {
            if (videoRef.current?.srcObject) {
                (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
            }
        };
    }
  }, [isFaceIdSetup, faceIdEnabled, view]);

  const verifyFaceWithAI = async (currentBase64: string) => {
    setIsVerifying(true);
    setAnalysisText("AI VERIFYING...");

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        let prompt = "";
        let parts: any[] = [];

        if (isFaceIdSetup) {
          prompt = "Analyze this camera frame for enrollment. Return exactly 'VALID' if you see a clear, well-lit human face looking directly at the camera. Return 'INVALID' if the image is blurry, dark, blocked, or contains no clear face. Answer in one word only.";
          parts = [
            { text: prompt },
            { inlineData: { mimeType: 'image/jpeg', data: currentBase64 } }
          ];
        } else if (faceIdReference) {
          prompt = "Security Check: Compare these two photos. Photo 1 is the authorized owner. Photo 2 is the person currently trying to unlock the device. Return exactly 'VALID' ONLY if Photo 2 clearly shows the same individual as Photo 1. If it is a different person, a photo of a photo, a mask, or if Photo 2 is too blurry/dark to confirm, return 'INVALID'. Be extremely strict. Answer in one word only.";
          parts = [
            { text: prompt },
            { inlineData: { mimeType: 'image/jpeg', data: faceIdReference } }, // Photo 1
            { inlineData: { mimeType: 'image/jpeg', data: currentBase64 } }    // Photo 2
          ];
        } else {
          throw new Error("No reference face found.");
        }

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: [{ parts }]
        });

        const result = response.text?.trim().toUpperCase();
        if (result === 'VALID') {
            setSuccess(true);
            onUnlock('faceid', currentBase64);
        } else {
            throw new Error("Face verification failed");
        }
    } catch (err) {
        setError(true);
        setAnalysisText("IDENTITY MISMATCH");
        setIsVerifying(false);
        setIsScanning(false);
        setScanProgress(0);
        setTimeout(() => {
            setError(false);
            setAnalysisText(isFaceIdSetup ? "RE-ENROLL" : "RETRY");
        }, 2000);
    }
  };

  const captureAndVerify = () => {
    if (!videoRef.current || !canvasRef.current) return;

    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const dataUrl = canvas.toDataURL('image/jpeg', 0.6);
    const base64 = dataUrl.split(',')[1];

    verifyFaceWithAI(base64);
  };

  const startFaceScan = () => {
    if (isScanning || isVerifying || success) return;
    setIsScanning(true);
    setScanProgress(0);
    setError(false);
    setAnalysisText("SCANNING...");

    let progress = 0;
    const interval = setInterval(() => {
        progress += 3;
        setScanProgress(Math.min(progress, 100));
        if (progress >= 100) {
            clearInterval(interval);
            captureAndVerify();
        }
    }, 30);
  };

  const handleKeypad = (num: string) => {
    if (input.length < 8) {
      setInput(prev => prev + num);
      setError(false);
    }
  };

  const handleBackspace = () => {
    setInput(prev => prev.slice(0, -1));
    setError(false);
  };

  const handleUnlock = () => {
    if (isSetup) {
      setView('setup-recovery');
      return;
    }
    const isValid = onUnlock(input);
    if (isValid) setSuccess(true);
    else {
      setError(true);
      setTimeout(() => setInput(''), 300);
    }
  };

  const handleRecoverySubmit = () => {
    const hashed = btoa(recoveryInput.toLowerCase().trim());
    if (hashed === recoveryAnswerHash) {
      setSuccess(true);
      onUnlock('recovery_success');
    } else {
      setError(true);
      setTimeout(() => setError(false), 500);
    }
  };

  const handleSetupRecoverySubmit = () => {
    if (!setupQuestion.trim() || !setupAnswer.trim()) {
      setError(true);
      setTimeout(() => setError(false), 500);
      return;
    }
    onUnlock(isRecoveryUpdate ? 'update_recovery' : input, { question: setupQuestion, answer: setupAnswer });
  };

  const stopFingerprintScan = (e?: React.PointerEvent) => {
    if (e) try { (e.currentTarget as HTMLElement).releasePointerCapture(e.pointerId); } catch(err) {}
    if (scanTimerRef.current) clearInterval(scanTimerRef.current);
    if (!success) {
      setIsScanning(false);
      setScanProgress(0);
      setAnalysisText('HOLD');
    }
  };

  const startFingerprintScan = (e: React.PointerEvent) => {
    if (!ready || isScanning || success) return;
    try { (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId); } catch(err) {}
    setIsScanning(true);
    setScanProgress(0);
    setError(false);

    const analysisSteps = ["Sampling...", "Mapping", "Verifying"];
    const duration = isFingerprintSetup ? 1200 : 800;
    const steps = duration / 16;
    let currentStep = 0;

    scanTimerRef.current = window.setInterval(() => {
        currentStep++;
        const progress = Math.min((currentStep / steps) * 100, 100);
        setScanProgress(progress);

        const textIdx = Math.floor((progress / 100) * analysisSteps.length);
        setAnalysisText(analysisSteps[textIdx] || "Verifying");

        if (currentStep >= steps) {
            clearInterval(scanTimerRef.current!);
            if (onUnlock('biometric')) setSuccess(true);
            else { setError(true); setIsScanning(false); setScanProgress(0); }
        }
    }, 16);
  };

  return (
    <div className="fixed inset-0 z-[110] bg-gray-950/98 backdrop-blur-3xl flex flex-col items-center justify-start py-4 px-2 select-none touch-none overflow-hidden">
      <div className={`absolute inset-0 transition-opacity duration-700 ${isScanning || isVerifying ? 'opacity-30' : 'opacity-0'} ${error ? 'bg-red-600/20' : 'bg-accent/20'} blur-[80px] pointer-events-none`} />

      <canvas ref={canvasRef} className="hidden" />

      <div className={`transition-all duration-700 origin-top mb-1 ${isFingerprintSetup || isFaceIdSetup || view !== 'unlock' ? 'scale-[0.3] opacity-0 h-0' : 'scale-[0.4] sm:scale-60'}`}>
        <Clock />
      </div>

      <div className={`w-full max-w-[240px] flex flex-col items-center space-y-2 transition-all duration-500 ${error ? 'animate-wiggle' : ''} ${success ? 'scale-125 opacity-0 pointer-events-none' : 'opacity-100'}`}>

        {/* Guard Header */}
        <div className="flex flex-col items-center gap-0.5">
          <div className={`p-1.5 rounded-lg transition-all duration-300 ${success ? 'bg-green-600 shadow-[0_0_20px_rgba(34,197,94,0.5)]' : error ? 'bg-red-600' : isVerifying ? 'bg-amber-600 animate-pulse' : isScanning ? 'bg-accent shadow-[0_0_15px_var(--accent-color)]' : 'bg-white/5'} text-white`}>
            {view === 'recovery' ? <MailIcon className="w-4 h-4" /> : isSetup || isRecoveryUpdate ? <ShieldCheckIcon className="w-4 h-4" /> : (isFaceIdSetup || faceIdEnabled) ? <FaceIdIcon className="w-4 h-4" /> : <FingerprintIcon className="w-4 h-4" />}
          </div>
          <div className="text-center">
            <h2 className="text-[10px] font-black text-white tracking-[0.1em] uppercase">Plus Guard</h2>
            <p className={`h-3 text-[8px] font-bold tracking-widest uppercase transition-colors ${success ? 'text-green-400' : error ? 'text-red-400' : isVerifying ? 'text-amber-400' : isScanning ? 'text-accent' : 'text-gray-500'}`}>
               {view === 'recovery' ? 'Recovery' : view === 'setup-recovery' ? (isRecoveryUpdate ? 'Update Recovery' : 'Recovery Setup') : success ? 'Authorized' : analysisText}
            </p>
          </div>
        </div>

        {view === 'unlock' && (
          <>
            {(isFaceIdSetup || faceIdEnabled) && (
                <div className={`relative w-28 h-28 rounded-full border-2 transition-colors duration-500 overflow-hidden bg-black mb-1 ${success ? 'border-green-500' : error ? 'border-red-500' : isVerifying ? 'border-amber-500' : 'border-white/10'}`}>
                    <video ref={videoRef} autoPlay playsInline muted className={`w-full h-full object-cover transition-all duration-500 ${success ? 'grayscale-0 brightness-100' : 'grayscale brightness-125'}`} />

                    {(isScanning || isVerifying) && (
                        <div className="absolute inset-0 z-10 pointer-events-none">
                            <div className={`w-full h-0.5 shadow-lg absolute top-0 left-0 animate-[face_1.5s_infinite_ease-in-out] ${isVerifying ? 'bg-amber-400 shadow-[0_0_15px_amber]' : 'bg-accent shadow-[0_0_15px_var(--accent-color)]'}`} />
                            <div className={`absolute inset-4 border-2 rounded-full animate-pulse ${isVerifying ? 'border-amber-400/30' : 'border-accent/30'}`} />
                        </div>
                    )}

                    {isFaceIdSetup && !isScanning && !isVerifying && (
                        <button onClick={startFaceScan} className="absolute inset-0 bg-accent/80 text-white text-[10px] font-bold uppercase flex flex-col items-center justify-center gap-1">
                            <FaceIdIcon className="w-6 h-6" />
                            Enroll Face
                        </button>
                    )}

                    {faceIdEnabled && error && !isScanning && !isVerifying && (
                        <button onClick={startFaceScan} className="absolute inset-0 bg-red-600/80 text-white text-[9px] font-bold uppercase flex items-center justify-center">Try Again</button>
                    )}
                </div>
            )}

            {!isFingerprintSetup && !isFaceIdSetup && !isScanning && !isVerifying && (
                <div className="flex flex-col items-center gap-4 w-full">
                    {/* PIN Indicator Dots */}
                    <div className="flex justify-center gap-2 h-4 items-center">
                        {Array.from({ length: Math.max(input.length, 4) }).map((_, i) => (
                            <div 
                                key={i} 
                                className={`w-2.5 h-2.5 rounded-full border-2 transition-all duration-200 ${
                                    i < input.length 
                                    ? 'bg-accent border-accent scale-125 shadow-[0_0_12px_var(--accent-color)]' 
                                    : 'border-accent/30 bg-accent/5'
                                }`} 
                            />
                        ))}
                    </div>

                    <div className="grid grid-cols-3 gap-1.5 w-full max-w-[150px]">
                        {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                            <button key={num} onClick={() => handleKeypad(num.toString())} className="aspect-square rounded-lg bg-white/5 text-white text-sm font-bold border border-white/5 active:bg-accent/30 transition-colors">{num}</button>
                        ))}
                        <button onClick={handleBackspace} className="aspect-square flex items-center justify-center text-white/20 active:text-white"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeWidth={2.5} d="M12 9.75L14.25 12m0 0l2.25 2.25M14.25 12l2.25-2.25M14.25 12L12 14.25m-2.58 4.92l-6.37-6.37a2.25 2.25 0 010-3.18l6.37-6.37A2.25 2.25 0 0110.47 2.25h10.28c1.242 0 2.25 1.008 2.25 2.25v15a2.25 2.25 0 01-2.25 2.25H10.47a2.25 2.25 0 01-1.47-.58z" /></svg></button>
                        <button onClick={() => handleKeypad('0')} className="aspect-square rounded-lg bg-white/5 text-white text-sm font-bold border border-white/5 active:bg-accent/30">0</button>
                        <button onClick={handleUnlock} disabled={input.length < 4} className="aspect-square flex items-center justify-center rounded-lg bg-accent text-white active:scale-95 disabled:opacity-5 shadow-lg"><svg className="w-4 h-4" fill="none" stroke="currentColor" strokeWidth={3} viewBox="0 0 24 24"><path d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" /></svg></button>
                    </div>

                    {!isSetup && recoveryQuestion && (
                      <button 
                        onClick={() => setView('recovery')}
                        className="text-[10px] text-accent hover:brightness-125 font-black uppercase tracking-widest mt-1 transition-all active:scale-95"
                      >
                        Forgot PIN?
                      </button>
                    )}
                </div>
            )}

            {(isFingerprintSetup || fingerprintEnabled) && !isFaceIdSetup && !faceIdEnabled && (
                <div className="relative flex flex-col items-center scale-90">
                    <svg className="absolute inset-[-10px] w-[calc(100%+20px)] h-[calc(100%+20px)] -rotate-90 pointer-events-none">
                        <circle cx="50%" cy="50%" r="24" className={`fill-none transition-all duration-150 ${success ? 'stroke-green-500' : isScanning ? 'stroke-accent' : 'stroke-white/5'}`} strokeWidth="4" strokeDasharray="150.8" strokeDashoffset={150.8 - (150.8 * scanProgress) / 100} strokeLinecap="round" />
                    </svg>
                    <button
                        onPointerDown={startFingerprintScan}
                        onPointerUp={stopFingerprintScan}
                        onPointerLeave={stopFingerprintScan}
                        className={`p-4 rounded-full border-2 transition-all relative z-10 ${success ? 'bg-green-600 text-white' : isScanning ? 'bg-accent text-white scale-110 shadow-lg shadow-accent/20' : 'bg-white/5 text-white/20'}`}
                    >
                        <FingerprintIcon className="w-8 h-8" />
                        {isScanning && <div className="absolute inset-0 animate-[laser_0.6s_infinite_linear] h-1 bg-white/30 shadow-xl" />}
                    </button>
                </div>
            )}
          </>
        )}

        {view === 'recovery' && (
          <div className="w-full space-y-4 animate-in fade-in slide-in-from-bottom-4">
             <div className="bg-white/5 border border-white/10 rounded-xl p-3">
                <p className="text-[10px] text-gray-500 uppercase font-black tracking-widest mb-1">Security Question</p>
                <p className="text-sm text-white font-medium">{recoveryQuestion}</p>
             </div>
             <input 
               type="text" 
               value={recoveryInput}
               onChange={(e) => setRecoveryInput(e.target.value)}
               placeholder="Answer..."
               className="w-full bg-white/5 border border-white/10 rounded-xl py-2 px-3 text-white text-sm focus:outline-none focus:ring-1 focus:ring-accent"
               autoFocus
             />
             <div className="flex gap-2">
                <button 
                  onClick={() => setView('unlock')}
                  className="flex-1 py-2 bg-white/5 text-gray-400 rounded-xl text-[10px] font-bold uppercase"
                >
                  Cancel
                </button>
                <button 
                  onClick={handleRecoverySubmit}
                  className="flex-1 py-2 bg-accent text-white rounded-xl text-[10px] font-bold uppercase shadow-lg shadow-accent/20"
                >
                  Verify
                </button>
             </div>
          </div>
        )}

        {view === 'setup-recovery' && (
          <div className="w-full space-y-3 animate-in fade-in slide-in-from-bottom-4">
             <div className="text-center mb-2">
                <p className="text-[9px] text-gray-500 uppercase font-black tracking-widest">
                  {isRecoveryUpdate ? 'Modify Recovery Layer' : 'Add Recovery Layer'}
                </p>
             </div>
             <input 
               type="text" 
               value={setupQuestion}
               onChange={(e) => setSetupQuestion(e.target.value)}
               placeholder="Security Question (e.g. First pet?)"
               className="w-full bg-white/5 border border-white/10 rounded-xl py-2 px-3 text-white text-xs focus:outline-none focus:ring-1 focus:ring-accent"
             />
             <input 
               type="text" 
               value={setupAnswer}
               onChange={(e) => setSetupAnswer(e.target.value)}
               placeholder="New Answer"
               className="w-full bg-white/5 border border-white/10 rounded-xl py-2 px-3 text-white text-xs focus:outline-none focus:ring-1 focus:ring-accent"
             />
             <div className="flex gap-2">
                {isRecoveryUpdate && onCancel && (
                    <button 
                        onClick={onCancel}
                        className="flex-1 py-2 bg-white/5 text-gray-400 rounded-xl text-[10px] font-bold uppercase"
                    >
                        Cancel
                    </button>
                )}
                <button 
                    onClick={handleSetupRecoverySubmit}
                    className="flex-1 py-2 bg-accent text-white rounded-xl text-[10px] font-bold uppercase shadow-lg shadow-accent/20"
                >
                    {isRecoveryUpdate ? 'Save Update' : 'Finish Setup'}
                </button>
             </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes laser { 0% { transform: translateY(-10px); } 100% { transform: translateY(60px); } }
        @keyframes face { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(112px); } }
        .animate-in { animation: animate-in 0.3s ease-out; }
        @keyframes animate-in {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

export default LockScreen;
